{
  "name": "M&D Finanças - Gestão Inteligente",
  "description": "Um sistema completo de gestão financeira pessoal para controle de gastos, receitas, pix crédito e fechamento mensal, agora reconstruído em React com alta performance."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type MonthStatus = 'ativo' | 'fechado';

export interface Month {
  id: number;
  nome: string;
  ano: number;
  status: MonthStatus;
  saldo_final: number;
  criado_em?: string;
}

export interface Bank {
  id: number;
  nome: string;
  cor: string;
}

export interface Revenue {
  id: number;
  mes_id: number;
  descricao: string;
  valor: number;
  data: string;
}

export interface Expense {
  id: number;
  mes_id: number;
  descricao: string;
  valor: number;
  pago: boolean;
  data: string;
}

export interface PixExpense {
  id: number;
  mes_id: number;
  descricao: string;
  valor_original: number;
  taxa_percentual: number;
  valor_final: number;
  pago: boolean;
  data: string;
}

export interface BankExpense {
  id: number;
  mes_id: number;
  banco_id: number;
  descricao: string;
  valor: number;
  pago: boolean;
  data: string;
}

import { createClient } from 'https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/+esm';

const SUPABASE_URL = 'https://bnhxmjcgyqwjombhrdks.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImJuaHhtamNneXF3am9tYmhyZGtzIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjQ4NDk3MDksImV4cCI6MjA4MDQyNTcwOX0.wg7k8DJhE29d24BzGwp5ltUx_x_4iXjQFOC55x3t4B8';

/**
 * FIX EXPLANATION:
 * The error "Identifier 'supabase' has already been declared" occurs because 
 * loading the library via CDN often attaches a global 'supabase' object to the window. 
 * Redeclaring 'let supabase' in the same scope causes a conflict.
 * 
 * SOLUTION: We name the instance 'supabaseClient' instead.
 */
export const supabaseClient = createClient(SUPABASE_URL, SUPABASE_KEY);

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  TrendingUp, 
  Banknote, 
  LockKeyhole, 
  Menu, 
  X,
  Wallet,
  User
} from 'lucide-react';
import { supabaseClient } from './services/supabase';
import { Month } from './types';
import Overview from './components/Overview';
import Expenses from './components/Expenses';
import Revenue from './components/Revenue';
import Banks from './components/Banks';
import Closing from './components/Closing';

const App: React.FC = () => {
  const [view, setView] = useState<string>('overview');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [currentMonth, setCurrentMonth] = useState<Month | null>(null);
  const [activeMonth, setActiveMonth] = useState<Month | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    try {
      const { data: meses } = await supabaseClient
        .from('meses')
        .select('*')
        .order('criado_em', { ascending: false });

      if (!meses || meses.length === 0) {
        const { data } = await supabaseClient
          .from('meses')
          .insert([{ nome: 'DEZEMBRO', ano: 2025, status: 'ativo' }])
          .select()
          .single();
        setCurrentMonth(data);
        setActiveMonth(data);
      } else {
        const active = meses.find((m: any) => m.status === 'ativo') || meses[0];
        setActiveMonth(active);
        setCurrentMonth(active);
      }
    } catch (error) {
      console.error("Initialization error:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleNavigate = (newView: string) => {
    setView(newView);
    setIsSidebarOpen(false);
  };

  const handleMonthChange = (month: Month) => {
    setCurrentMonth(month);
  };

  if (loading || !currentMonth) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 animate-spin rounded-full border-4 border-green-700 border-t-transparent"></div>
          <p className="font-medium text-gray-600">Carregando finanças...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden text-gray-900">
      {/* Mobile Menu Button */}
      <button 
        className="fixed top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md lg:hidden"
        onClick={() => setIsSidebarOpen(!isSidebarOpen)}
      >
        {isSidebarOpen ? <X /> : <Menu />}
      </button>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r border-gray-200 transform transition-transform duration-300 ease-in-out lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="flex flex-col h-full p-6">
          <div className="flex items-center gap-3 mb-10 text-green-800">
            <div className="bg-green-100 p-2 rounded-full">
              <Wallet size={24} />
            </div>
            <span className="text-xl font-bold">M&D Finanças</span>
          </div>

          <nav className="flex-1 space-y-1">
            <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-4 px-2">Menu Principal</p>
            <NavItem 
              icon={<LayoutDashboard size={20} />} 
              label="Visão Geral" 
              active={view === 'overview'} 
              onClick={() => handleNavigate('overview')} 
            />
            <NavItem 
              icon={<Receipt size={20} />} 
              label="Despesas" 
              active={view === 'expenses'} 
              onClick={() => handleNavigate('expenses')} 
            />
            <NavItem 
              icon={<TrendingUp size={20} />} 
              label="Receitas" 
              active={view === 'revenue'} 
              onClick={() => handleNavigate('revenue')} 
            />

            <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mt-8 mb-4 px-2">Gestão</p>
            <NavItem 
              icon={<Banknote size={20} />} 
              label="Bancos" 
              active={view === 'banks'} 
              onClick={() => handleNavigate('banks')} 
            />
            <NavItem 
              icon={<LockKeyhole size={20} />} 
              label="Histórico / Fechamento" 
              active={view === 'closing'} 
              onClick={() => handleNavigate('closing')} 
            />
          </nav>

          <div className="mt-auto pt-6 border-t border-gray-100">
            <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-xl">
              <div className="bg-white p-2 rounded-full border border-gray-200">
                <User size={18} className="text-gray-600" />
              </div>
              <div className="flex flex-col">
                <span className="text-sm font-bold">M&D Admin</span>
                <span className="text-xs text-gray-500">Plano Premium</span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 lg:p-10 relative">
        <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
          <div>
            <h1 className="text-2xl lg:text-3xl font-bold text-gray-900">
              {view === 'overview' && 'Visão Geral'}
              {view === 'expenses' && 'Minhas Despesas'}
              {view === 'revenue' && 'Entradas e Receitas'}
              {view === 'banks' && 'Bancos e Instituições'}
              {view === 'closing' && 'Controle de Período'}
            </h1>
            <p className="text-gray-500">Ref: {currentMonth.nome} {currentMonth.ano}</p>
          </div>

          <div className="flex items-center gap-3">
            {currentMonth.status === 'fechado' && activeMonth && currentMonth.id !== activeMonth.id && (
              <button 
                onClick={() => setCurrentMonth(activeMonth)}
                className="px-4 py-2 text-sm font-medium bg-white border border-gray-300 rounded-full hover:bg-gray-50 transition shadow-sm"
              >
                Voltar ao Mês Atual
              </button>
            )}
            <div className={`px-4 py-2 rounded-full text-sm font-semibold shadow-sm ${
              currentMonth.status === 'ativo' ? 'bg-green-600 text-white' : 'bg-red-500 text-white'
            }`}>
              {currentMonth.status === 'ativo' ? 'Mês Ativo' : 'Mês Fechado'}
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'overview' && <Overview currentMonth={currentMonth} refresh={init} />}
          {view === 'expenses' && <Expenses currentMonth={currentMonth} />}
          {view === 'revenue' && <Revenue currentMonth={currentMonth} />}
          {view === 'banks' && <Banks currentMonth={currentMonth} />}
          {view === 'closing' && <Closing currentMonth={currentMonth} onSelectMonth={handleMonthChange} onRefresh={init} />}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 font-medium ${
      active 
        ? 'bg-green-700 text-white shadow-lg shadow-green-900/20' 
        : 'text-gray-500 hover:bg-gray-50 hover:text-green-700'
    }`}
  >
    {icon}
    <span>{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { TrendingDown, TrendingUp, Wallet, ArrowRight } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month } from '../types';

interface OverviewProps {
  currentMonth: Month;
  refresh: () => void;
}

const Overview: React.FC<OverviewProps> = ({ currentMonth, refresh }) => {
  const [totals, setTotals] = useState({ revenue: 0, expenses: 0, balance: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  const fetchData = async () => {
    setLoading(true);
    const [receitas, despesas, pix, bancos] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id)
    ]);

    const rev = receitas.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;
    const exp = (despesas.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0) +
                (pix.data?.reduce((acc, curr) => acc + curr.valor_final, 0) || 0) +
                (bancos.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0);

    setTotals({
      revenue: rev,
      expenses: exp,
      balance: rev - exp
    });
    setLoading(false);
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (loading) return <div className="text-center py-20 animate-pulse text-gray-400">Calculando saldos...</div>;

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-green-900 text-white p-8 rounded-[2rem] shadow-xl relative overflow-hidden group">
          <div className="absolute -right-4 -top-4 bg-white/10 p-12 rounded-full transition-transform group-hover:scale-110"></div>
          <p className="text-green-100/70 font-medium mb-1 flex items-center gap-2">
            <Wallet size={16} /> Saldo Geral
          </p>
          <h2 className="text-4xl font-bold tracking-tight">{formatCurrency(totals.balance)}</h2>
          <p className="mt-4 text-sm text-green-100/50">Disponível para investimentos ou reserva</p>
        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-green-100 p-3 rounded-2xl text-green-700">
              <TrendingUp size={24} />
            </div>
            <span className="text-xs font-bold text-green-600 bg-green-50 px-2 py-1 rounded-md">+100% Entradas</span>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-sm font-medium">Entradas</p>
            <h2 className="text-2xl font-bold">{formatCurrency(totals.revenue)}</h2>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-red-100 p-3 rounded-2xl text-red-600">
              <TrendingDown size={24} />
            </div>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-sm font-medium">Saídas</p>
            <h2 className="text-2xl font-bold">{formatCurrency(totals.expenses)}</h2>
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold mb-6">Ações Rápidas</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <QuickAction color="bg-blue-50 text-blue-700" label="Ver Extrato" icon={<TrendingUp size={18} />} />
          <QuickAction color="bg-orange-50 text-orange-700" label="Lançar Boleto" icon={<TrendingDown size={18} />} />
          <QuickAction color="bg-purple-50 text-purple-700" label="Gestão Bancária" icon={<Wallet size={18} />} />
          <QuickAction color="bg-gray-50 text-gray-700" label="Dicas de IA" icon={<ArrowRight size={18} />} />
        </div>
      </div>
    </div>
  );
};

const QuickAction: React.FC<{ color: string, label: string, icon: React.ReactNode }> = ({ color, label, icon }) => (
  <button className={`${color} p-4 rounded-2xl flex items-center gap-3 font-semibold transition hover:opacity-80`}>
    {icon}
    <span className="text-sm">{label}</span>
  </button>
);

export default Overview;

import React, { useState, useEffect } from 'react';
import { Receipt, Lightning, Plus, Trash2, CheckCircle2, Circle } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Expense, PixExpense } from '../types';

interface ExpensesProps {
  currentMonth: Month;
}

const Expenses: React.FC<ExpensesProps> = ({ currentMonth }) => {
  const [activeTab, setActiveTab] = useState<'contas' | 'pix'>('contas');
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [pixExpenses, setPixExpenses] = useState<PixExpense[]>([]);
  const [pixTax, setPixTax] = useState(5.0);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchPixConfig();
    fetchData();
  }, [currentMonth, activeTab]);

  const fetchPixConfig = async () => {
    const { data } = await supabaseClient.from('configuracoes').select('*').eq('chave', 'taxa_pix').single();
    if (data) setPixTax(parseFloat(data.valor));
  };

  const fetchData = async () => {
    setLoading(true);
    if (activeTab === 'contas') {
      const { data } = await supabaseClient
        .from('despesas_contas')
        .select('*')
        .eq('mes_id', currentMonth.id)
        .order('data', { ascending: true });
      setExpenses(data || []);
    } else {
      const { data } = await supabaseClient
        .from('despesas_pix_credito')
        .select('*')
        .eq('mes_id', currentMonth.id)
        .order('data', { ascending: true });
      setPixExpenses(data || []);
    }
    setLoading(false);
  };

  const handleTogglePaid = async (table: string, id: number, currentStatus: boolean) => {
    if (currentMonth.status === 'fechado') return;
    await supabaseClient.from(table).update({ pago: !currentStatus }).eq('id', id);
    fetchData();
  };

  const handleDelete = async (table: string, id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Deseja realmente excluir?")) return;
    await supabaseClient.from(table).delete().eq('id', id);
    fetchData();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(formData.val.replace(',', '.'));
    if (!formData.desc || isNaN(val)) return;

    if (activeTab === 'contas') {
      await supabaseClient.from('despesas_contas').insert([{
        mes_id: currentMonth.id,
        descricao: formData.desc,
        valor: val,
        data: formData.date
      }]);
    } else {
      const finalVal = val + (val * (pixTax / 100));
      await supabaseClient.from('despesas_pix_credito').insert([{
        mes_id: currentMonth.id,
        descricao: formData.desc,
        valor_original: val,
        taxa_percentual: pixTax,
        valor_final: finalVal,
        data: formData.date
      }]);
    }

    setShowModal(false);
    setFormData({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });
    fetchData();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap gap-2 p-1 bg-gray-200/50 rounded-2xl w-fit">
        <button 
          onClick={() => setActiveTab('contas')}
          className={`px-6 py-2 rounded-xl text-sm font-bold transition ${activeTab === 'contas' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500'}`}
        >
          Contas Fixas
        </button>
        <button 
          onClick={() => setActiveTab('pix')}
          className={`px-6 py-2 rounded-xl text-sm font-bold transition ${activeTab === 'pix' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500'}`}
        >
          Pix Crédito
        </button>
      </div>

      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-xl font-bold flex items-center gap-2">
            {activeTab === 'contas' ? <Receipt /> : <Lightning />}
            {activeTab === 'contas' ? 'Listagem de Contas' : `Pix Crédito (Taxa: ${pixTax}%)`}
          </h3>
          {currentMonth.status === 'ativo' && (
            <button 
              onClick={() => setShowModal(true)}
              className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2 hover:bg-green-900 transition shadow-lg shadow-green-900/10"
            >
              <Plus size={18} /> Novo Lançamento
            </button>
          )}
        </div>

        {loading ? (
          <div className="py-12 text-center text-gray-400">Buscando despesas...</div>
        ) : (
          <div className="space-y-2">
            {activeTab === 'contas' ? (
              expenses.length === 0 ? <p className="text-center py-10 text-gray-400">Nenhuma conta este mês.</p> :
              expenses.map(exp => (
                <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border transition ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100'}`}>
                  <div className="flex items-center gap-4">
                    <button 
                      onClick={() => handleTogglePaid('despesas_contas', exp.id, exp.pago)}
                      className={`transition ${exp.pago ? 'text-green-600' : 'text-gray-300 hover:text-green-400'}`}
                    >
                      {exp.pago ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                    </button>
                    <div>
                      <h4 className={`font-bold ${exp.pago ? 'line-through text-gray-400' : 'text-gray-800'}`}>{exp.descricao}</h4>
                      <p className="text-xs text-gray-400 font-medium uppercase tracking-tighter">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-6">
                    <span className="font-bold text-lg">{formatCurrency(exp.valor)}</span>
                    {currentMonth.status === 'ativo' && (
                      <button onClick={() => handleDelete('despesas_contas', exp.id)} className="text-gray-300 hover:text-red-500 transition">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))
            ) : (
              pixExpenses.length === 0 ? <p className="text-center py-10 text-gray-400">Nenhum Pix este mês.</p> :
              pixExpenses.map(exp => (
                <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border transition ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100'}`}>
                   <div className="flex items-center gap-4">
                    <button 
                      onClick={() => handleTogglePaid('despesas_pix_credito', exp.id, exp.pago)}
                      className={`transition ${exp.pago ? 'text-green-600' : 'text-gray-300 hover:text-green-400'}`}
                    >
                      {exp.pago ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                    </button>
                    <div>
                      <h4 className={`font-bold ${exp.pago ? 'line-through text-gray-400' : 'text-gray-800'}`}>{exp.descricao}</h4>
                      <p className="text-xs text-gray-400 font-medium">Orig: {formatCurrency(exp.valor_original)} (+{exp.taxa_percentual}%)</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-6">
                    <span className="font-bold text-lg">{formatCurrency(exp.valor_final)}</span>
                    {currentMonth.status === 'ativo' && (
                      <button onClick={() => handleDelete('despesas_pix_credito', exp.id)} className="text-gray-300 hover:text-red-500 transition">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl animate-in fade-in zoom-in duration-200">
            <h2 className="text-2xl font-bold mb-6">Novo Lançamento</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-1">Descrição</label>
                <input 
                  type="text" 
                  value={formData.desc} 
                  onChange={e => setFormData({...formData, desc: e.target.value})}
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-green-700 outline-none"
                  placeholder="Ex: Aluguel, Supermercado..."
                  required
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">Valor</label>
                  <input 
                    type="text" 
                    value={formData.val} 
