  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabaseClient
      .from('receitas')
      .select('*')
      .eq('mes_id', currentMonth.id)
      .order('data', { ascending: true });
    setRevenues(data || []);
    setLoading(false);
  };

  const handleDelete = async (id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Deseja excluir esta receita?")) return;
    await supabaseClient.from('receitas').delete().eq('id', id);
    fetchData();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(formData.val.replace(',', '.'));
    if (!formData.desc || isNaN(val)) return;

    await supabaseClient.from('receitas').insert([{
      mes_id: currentMonth.id,
      descricao: formData.desc,
      valor: val,
      data: formData.date
