import React, { useState, useEffect } from 'react';
import { Banknote, Plus, ChevronRight, ArrowLeft, Trash2, CheckCircle2, Circle } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Bank, BankExpense } from '../types';

interface BanksProps {
  currentMonth: Month;
}

const Banks: React.FC<BanksProps> = ({ currentMonth }) => {
  const [banks, setBanks] = useState<Bank[]>([]);
  const [selectedBank, setSelectedBank] = useState<Bank | null>(null);
  const [bankExpenses, setBankExpenses] = useState<BankExpense[]>([]);
  const [loading, setLoading] = useState(true);
  const [showBankModal, setShowBankModal] = useState(false);
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [bankForm, setBankForm] = useState({ nome: '', cor: '#15803d' });
  const [expForm, setExpForm] = useState({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchBanks();
  }, []);

  useEffect(() => {
    if (selectedBank) fetchBankExpenses();
  }, [selectedBank, currentMonth]);

  const fetchBanks = async () => {
    const { data } = await supabaseClient.from('bancos').select('*');
    setBanks(data || []);
    setLoading(false);
  };

  const fetchBankExpenses = async () => {
    if (!selectedBank) return;
    const { data } = await supabaseClient
      .from('banco_despesas')
      .select('*')
      .eq('banco_id', selectedBank.id)
      .eq('mes_id', currentMonth.id)
      .order('data', { ascending: true });
    setBankExpenses(data || []);
  };

  const handleCreateBank = async (e: React.FormEvent) => {
    e.preventDefault();
    await supabaseClient.from('bancos').insert([bankForm]);
    setShowBankModal(false);
    setBankForm({ nome: '', cor: '#15803d' });
    fetchBanks();
  };

  const handleCreateExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBank) return;
    const val = parseFloat(expForm.val.replace(',', '.'));
    await supabaseClient.from('banco_despesas').insert([{
      mes_id: currentMonth.id,
      banco_id: selectedBank.id,
      descricao: expForm.desc,
      valor: val,
      data: expForm.date
    }]);
    setShowExpenseModal(false);
    setExpForm({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });
    fetchBankExpenses();
  };

  const handleTogglePaid = async (id: number, current: boolean) => {
    if (currentMonth.status === 'fechado') return;
    await supabaseClient.from('banco_despesas').update({ pago: !current }).eq('id', id);
    fetchBankExpenses();
  };

  const handleDeleteExpense = async (id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Remover despesa?")) return;
    await supabaseClient.from('banco_despesas').delete().eq('id', id);
    fetchBankExpenses();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (selectedBank) {
    const total = bankExpenses.reduce((acc, curr) => acc + curr.valor, 0);
    return (
      <div className="space-y-6 animate-in slide-in-from-right duration-300">
        <button 
          onClick={() => setSelectedBank(null)}
          className="flex items-center gap-2 text-gray-500 hover:text-gray-900 transition font-medium"
        >
          <ArrowLeft size={18} /> Voltar para Bancos
        </button>

        <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
          <div className="flex justify-between items-center mb-8">
            <div className="flex items-center gap-4">
              <div 
                className="w-12 h-12 rounded-2xl flex items-center justify-center text-white" 
                style={{ backgroundColor: selectedBank.cor }}
              >
                <Banknote size={24} />
              </div>
              <div>
                <h3 className="text-2xl font-bold">{selectedBank.nome}</h3>
                <p className="text-sm text-gray-500 font-medium">Total no mês: {formatCurrency(total)}</p>
              </div>
            </div>
            {currentMonth.status === 'ativo' && (
              <button 
                onClick={() => setShowExpenseModal(true)}
                className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
              >
                <Plus size={18} /> Novo Lançamento
              </button>
            )}
          </div>

          <div className="space-y-2">
            {bankExpenses.length === 0 ? <p className="text-center py-20 text-gray-400">Nenhum gasto neste banco.</p> :
            bankExpenses.map(exp => (
              <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100'}`}>
                <div className="flex items-center gap-4">
                  <button onClick={() => handleTogglePaid(exp.id, exp.pago)} className={`${exp.pago ? 'text-green-600' : 'text-gray-300'}`}>
                    {exp.pago ? <CheckCircle2 /> : <Circle />}
                  </button>
                  <div>
                    <h4 className={`font-bold ${exp.pago ? 'line-through text-gray-400' : ''}`}>{exp.descricao}</h4>
                    <p className="text-xs text-gray-400 font-medium uppercase">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                  </div>
                </div>
                <div className="flex items-center gap-6">
                  <span className="font-bold text-lg">{formatCurrency(exp.valor)}</span>
                  {currentMonth.status === 'ativo' && (
                    <button onClick={() => handleDeleteExpense(exp.id)} className="text-gray-300 hover:text-red-500 transition">
                      <Trash2 size={18} />
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>

        {showExpenseModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl">
              <h2 className="text-2xl font-bold mb-6">Lançamento em {selectedBank.nome}</h2>
              <form onSubmit={handleCreateExpense} className="space-y-4">
                <input type="text" placeholder="Descrição" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.desc} onChange={e => setExpForm({...expForm, desc: e.target.value})} required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="text" placeholder="Valor (0,00)" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.val} onChange={e => setExpForm({...expForm, val: e.target.value})} required />
                  <input type="date" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.date} onChange={e => setExpForm({...expForm, date: e.target.value})} required />
                </div>
                <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setShowExpenseModal(false)} className="flex-1 bg-gray-100 py-3 rounded-xl font-bold">Cancelar</button>
                  <button type="submit" className="flex-1 bg-green-800 text-white py-3 rounded-xl font-bold">Lançar</button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold">Instituições Financeiras</h3>
        {currentMonth.status === 'ativo' && (
          <button 
            onClick={() => setShowBankModal(true)}
            className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
          >
            <Plus size={18} /> Novo Banco
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {banks.map(bank => (
          <button 
            key={bank.id}
            onClick={() => setSelectedBank(bank)}
            className="group relative bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 transition-all hover:shadow-xl hover:-translate-y-1 text-left overflow-hidden"
          >
            <div 
              className="absolute top-0 right-0 w-32 h-32 -mr-10 -mt-10 rounded-full opacity-10 group-hover:scale-125 transition-transform"
              style={{ backgroundColor: bank.cor }}
            ></div>
            <div 
              className="w-12 h-12 rounded-2xl flex items-center justify-center text-white mb-6 shadow-lg"
              style={{ backgroundColor: bank.cor }}
            >
              <Banknote size={24} />
            </div>
            <div className="flex justify-between items-end">
              <div>
                <h4 className="text-xl font-bold text-gray-800">{bank.nome}</h4>
                <p className="text-sm text-gray-400 font-medium">Gestão de Crédito</p>
              </div>
              <ChevronRight className="text-gray-300 group-hover:text-green-700 transition" />
            </div>
          </button>
        ))}
      </div>

      {showBankModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl">
            <h2 className="text-2xl font-bold mb-6">Nova Instituição</h2>
            <form onSubmit={handleCreateBank} className="space-y-4">
              <input type="text" placeholder="Nome do Banco" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={bankForm.nome} onChange={e => setBankForm({...bankForm, nome: e.target.value})} required />
              <div className="flex items-center gap-4">
                <label className="text-sm font-bold text-gray-600">Cor de Destaque</label>
                <input type="color" className="w-20 h-10 rounded cursor-pointer" value={bankForm.cor} onChange={e => setBankForm({...bankForm, cor: e.target.value})} />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowBankModal(false)} className="flex-1 bg-gray-100 py-3 rounded-xl font-bold">Cancelar</button>
                <button type="submit" className="flex-1 bg-green-800 text-white py-3 rounded-xl font-bold">Criar Banco</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Banks;

import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    const { data } = await supabaseClient
      .from('meses')
      .select('*')
      .order('criado_em', { ascending: false });
    setMonths(data || []);
    setLoading(false);
  };

  const closeMonthRoutine = async () => {
    if (!confirm("Isso fechará o mês atual e criará o próximo. Deseja continuar?")) return;

    // 1. Calcular Saldo Final
    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    // 2. Atualizar mês atual como fechado
    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // 3. Criar próximo mês
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome);
    let nextIdx = idx + 1;
    let nextYear = currentMonth.ano;
    if (nextIdx > 11) { nextIdx = 0; nextYear++; }

    await supabaseClient.from('meses').insert([{ nome: meses_nomes[nextIdx], ano: nextYear, status: 'ativo' }]);

    alert("Mês fechado com sucesso!");
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8">
      {currentMonth.status === 'ativo' && (
        <div className="bg-red-50 border border-red-100 p-8 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="bg-red-100 p-4 rounded-full text-red-700">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-xl font-bold text-red-900">Encerrar Ciclo Mensal</h3>
              <p className="text-red-700/60 max-w-sm">Ao fechar o mês, você bloqueia novas edições e inicia o planejamento do próximo período.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="bg-red-600 text-white px-8 py-3 rounded-full font-bold hover:bg-red-700 transition shadow-lg shadow-red-600/20"
          >
            Fechar Mês de {currentMonth.nome}
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
        <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
          <Calendar className="text-gray-400" />
          Histórico de Meses
        </h3>

        {loading ? <p className="text-center py-10">Carregando histórico...</p> : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div key={m.id} className="p-6 rounded-2xl border border-gray-100 bg-gray-50/30 flex items-center justify-between group hover:border-green-200 transition">
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl ${m.status === 'ativo' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                    {m.status === 'ativo' ? <Unlock size={20} /> : <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-800 uppercase tracking-tight">{m.nome} / {m.ano}</h4>
                    <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-0.5 rounded-md ${m.status === 'ativo' ? 'bg-green-100 text-green-700' : 'bg-gray-200 text-gray-500'}`}>
                      {m.status}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-lg font-bold text-gray-900">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-xs text-gray-400 font-medium">Em andamento</p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-1 text-xs font-bold text-green-700 hover:underline flex items-center gap-1 ml-auto"
                  >
                    Visualizar <TrendingUp size={12} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { Receipt, Zap, Plus, Trash2, CheckCircle2, Circle } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Expense, PixExpense } from '../types';

interface ExpensesProps {
