      await supabaseClient.from('receitas').update(payload).eq('id', editingId);
    } else {
      await supabaseClient.from('receitas').insert([payload]);
    }

    setShowModal(false);
    setEditingId(null);
    setFormData({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });
    fetchData();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-xl font-bold flex items-center gap-2">
            <TrendingUp className="text-green-600" />
            Entradas Financeiras
          </h3>
          {currentMonth.status === 'ativo' && (
            <button 
              onClick={() => { setEditingId(null); setFormData({ desc: '', val: '', date: new Date().toISOString().split('T')[0] }); setShowModal(true); }}
              className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2 hover:bg-green-900 transition shadow-lg shadow-green-900/10"
            >
              <Plus size={18} /> Nova Receita
            </button>
          )}
        </div>

        {loading ? (
          <div className="py-12 text-center text-gray-400">Buscando receitas...</div>
        ) : (
          <div className="space-y-4">
            {revenues.length === 0 ? <p className="text-center py-10 text-gray-400">Nenhuma entrada este mês.</p> :
            revenues.map(rev => (
              <div key={rev.id} className="flex items-center justify-between p-6 rounded-2xl bg-green-50/30 border border-green-100 transition hover:bg-green-50/50">
                <div className="flex items-center gap-4">
                  <div className="bg-white p-3 rounded-full text-green-700 shadow-sm">
                    <TrendingUp size={20} />
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-800">{rev.descricao}</h4>
                    <p className="text-xs text-gray-400 font-medium uppercase">{new Date(rev.data).toLocaleDateString('pt-BR')}</p>
                  </div>
                </div>
                <div className="flex items-center gap-6">
                  <span className="font-bold text-xl text-green-700">{formatCurrency(rev.valor)}</span>
                  <div className="flex items-center gap-2">
                    {currentMonth.status === 'ativo' && (
                      <>
                        <button onClick={() => openEditModal(rev)} className="text-gray-300 hover:text-blue-600 transition p-2">
                          <Pencil size={18} />
                        </button>
                        <button onClick={() => handleDelete(rev.id)} className="text-gray-300 hover:text-red-500 transition p-2">
                          <Trash2 size={18} />
                        </button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl animate-in fade-in zoom-in duration-200">
            <h2 className="text-2xl font-bold mb-6 text-green-800">{editingId ? 'Editar Receita' : 'Nova Receita'}</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-1">Descrição</label>
                <input 
                  type="text" 
                  value={formData.desc} 
                  onChange={e => setFormData({...formData, desc: e.target.value})}
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-green-700 outline-none"
                  placeholder="Ex: Salário, Vendas..."
                  required
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">Valor</label>
                  <input 
                    type="text" 
                    value={formData.val} 
                    onChange={e => setFormData({...formData, val: e.target.value})}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-green-700 outline-none"
                    placeholder="0,00"
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">Data</label>
                  <input 
                    type="date" 
                    value={formData.date} 
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-green-700 outline-none"
                    required
                  />
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => { setShowModal(false); setEditingId(null); }} className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-xl hover:bg-gray-200 transition">Cancelar</button>
                <button type="submit" className="flex-1 bg-green-800 text-white font-bold py-3 rounded-xl hover:bg-green-900 transition shadow-lg shadow-green-900/20">{editingId ? 'Atualizar' : 'Salvar Receita'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Revenue;

import React, { useState, useEffect } from 'react';
import { Banknote, Plus, ChevronRight, ArrowLeft, Trash2, CheckCircle2, Circle, Save, Info } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Bank, BankExpense } from '../types';

interface BanksProps {
  currentMonth: Month;
}

const Banks: React.FC<BanksProps> = ({ currentMonth }) => {
  const [banks, setBanks] = useState<Bank[]>([]);
  const [selectedBank, setSelectedBank] = useState<Bank | null>(null);
  const [bankExpenses, setBankExpenses] = useState<BankExpense[]>([]);
  const [loading, setLoading] = useState(true);

  // Custom states for special banks
  const [specialFields, setSpecialFields] = useState<{ [key: string]: string }>({});
  const [saving, setSaving] = useState(false);

  const [showBankModal, setShowBankModal] = useState(false);
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [bankForm, setBankForm] = useState({ nome: '', cor: '#15803d' });
  const [expForm, setExpForm] = useState({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchBanks();
  }, []);

  useEffect(() => {
    if (selectedBank) {
      fetchBankExpenses();
    }
  }, [selectedBank, currentMonth]);

  const fetchBanks = async () => {
    const { data } = await supabaseClient.from('bancos').select('*');
    setBanks(data || []);
    setLoading(false);
  };

  const fetchBankExpenses = async () => {
    if (!selectedBank) return;
    const { data } = await supabaseClient
      .from('banco_despesas')
      .select('*')
      .eq('banco_id', selectedBank.id)
      .eq('mes_id', currentMonth.id)
      .order('data', { ascending: true });

    setBankExpenses(data || []);

    // Load special fields if AMEX or BB
    if (selectedBank.nome === 'American Express' || selectedBank.nome === 'BB') {
      const initialFields: { [key: string]: string } = {};
      const fields = selectedBank.nome === 'American Express' 
        ? ['Compras à Vista', 'Em Processamento'] 
        : ['Compras à Vista', 'Em Processamento', 'Parceladas'];

      fields.forEach(f => {
        const found = data?.find(d => d.descricao === f);
        initialFields[f] = found ? found.valor.toString().replace('.', ',') : '';
      });
      setSpecialFields(initialFields);
    }
  };

  const handleSaveSpecial = async () => {
    if (!selectedBank) return;
    setSaving(true);
    try {
      const fields = Object.keys(specialFields);
      for (const field of fields) {
        const val = parseFloat(specialFields[field].replace(',', '.')) || 0;

        // Find existing record
        const existing = bankExpenses.find(e => e.descricao === field);

        if (existing) {
          await supabaseClient.from('banco_despesas').update({ valor: val }).eq('id', existing.id);
        } else {
          await supabaseClient.from('banco_despesas').insert([{
            mes_id: currentMonth.id,
            banco_id: selectedBank.id,
            descricao: field,
            valor: val,
            data: new Date().toISOString().split('T')[0]
          }]);
        }
      }
      alert("Valores atualizados com sucesso!");
      fetchBankExpenses();
    } catch (error) {
      console.error(error);
      alert("Erro ao salvar.");
    } finally {
      setSaving(false);
    }
  };

  const handleCreateBank = async (e: React.FormEvent) => {
    e.preventDefault();
    await supabaseClient.from('bancos').insert([bankForm]);
    setShowBankModal(false);
    setBankForm({ nome: '', cor: '#15803d' });
    fetchBanks();
  };

  const handleCreateExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBank) return;
    const val = parseFloat(expForm.val.replace(',', '.'));
    await supabaseClient.from('banco_despesas').insert([{
      mes_id: currentMonth.id,
      banco_id: selectedBank.id,
      descricao: expForm.desc,
      valor: val,
      data: expForm.date
    }]);
    setShowExpenseModal(false);
    setExpForm({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });
    fetchBankExpenses();
  };

  const handleTogglePaid = async (id: number, current: boolean) => {
    if (currentMonth.status === 'fechado') return;
    await supabaseClient.from('banco_despesas').update({ pago: !current }).eq('id', id);
    fetchBankExpenses();
  };

  const handleDeleteExpense = async (id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Remover despesa?")) return;
    await supabaseClient.from('banco_despesas').delete().eq('id', id);
    fetchBankExpenses();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (selectedBank) {
    const total = bankExpenses.reduce((acc, curr) => acc + curr.valor, 0);
    const isSpecial = selectedBank.nome === 'American Express' || selectedBank.nome === 'BB';

    return (
      <div className="space-y-6 animate-in slide-in-from-right duration-300">
        <button 
          onClick={() => setSelectedBank(null)}
          className="flex items-center gap-2 text-gray-500 hover:text-gray-900 transition font-medium"
        >
          <ArrowLeft size={18} /> Voltar para Bancos
        </button>

        <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
          <div className="flex justify-between items-center mb-8">
            <div className="flex items-center gap-4">
              <div 
                className="w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-inner" 
                style={{ backgroundColor: selectedBank.cor }}
              >
                <Banknote size={24} />
              </div>
              <div>
                <h3 className="text-2xl font-bold">{selectedBank.nome}</h3>
                <p className="text-sm text-gray-500 font-medium">Total Acumulado: {formatCurrency(total)}</p>
              </div>
            </div>
            {!isSpecial && currentMonth.status === 'ativo' && (
              <button 
                onClick={() => setShowExpenseModal(true)}
                className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
              >
                <Plus size={18} /> Novo Lançamento
              </button>
            )}
          </div>

          {isSpecial ? (
            <div className="max-w-xl mx-auto space-y-6 bg-gray-50 p-8 rounded-3xl border border-gray-100">
              <div className="flex items-center gap-2 text-blue-600 mb-4 bg-blue-50 p-3 rounded-xl border border-blue-100">
                <Info size={18} />
                <span className="text-xs font-bold">Gerencie os valores fixos do cartão. O sistema somará todos automaticamente.</span>
              </div>

              <div className="space-y-4">
                {Object.keys(specialFields).map(f => (
                  <div key={f}>
                    <label className="block text-sm font-bold text-gray-700 mb-1">{f}</label>
                    <input 
                      type="text"
                      value={specialFields[f]}
                      onChange={e => setSpecialFields({...specialFields, [f]: e.target.value})}
                      placeholder="0,00"
                      className="w-full bg-white border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700 font-bold text-lg"
                      disabled={currentMonth.status === 'fechado'}
                    />
                  </div>
                ))}
              </div>

              {currentMonth.status === 'ativo' && (
                <button 
                  onClick={handleSaveSpecial}
                  disabled={saving}
                  className="w-full bg-green-800 text-white font-bold py-4 rounded-2xl shadow-lg shadow-green-900/20 hover:bg-green-900 transition flex items-center justify-center gap-2"
                >
                  {saving ? <div className="h-5 w-5 animate-spin rounded-full border-2 border-white border-t-transparent" /> : <Save size={20} />}
                  Salvar Alterações
                </button>
              )}
            </div>
          ) : (
            <div className="space-y-2">
              {bankExpenses.length === 0 ? <p className="text-center py-20 text-gray-400">Nenhum gasto neste banco.</p> :
              bankExpenses.map(exp => (
                <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100 hover:border-green-200'}`}>
                  <div className="flex items-center gap-4">
                    <button onClick={() => handleTogglePaid(exp.id, exp.pago)} className={`${exp.pago ? 'text-green-600' : 'text-gray-300'}`}>
                      {exp.pago ? <CheckCircle2 /> : <Circle />}
                    </button>
                    <div>
                      <h4 className={`font-bold ${exp.pago ? 'line-through text-gray-400' : ''}`}>{exp.descricao}</h4>
                      <p className="text-xs text-gray-400 font-medium uppercase">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-6">
                    <span className="font-bold text-lg">{formatCurrency(exp.valor)}</span>
                    {currentMonth.status === 'ativo' && (
                      <button onClick={() => handleDeleteExpense(exp.id)} className="text-gray-300 hover:text-red-500 transition">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {showExpenseModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl">
              <h2 className="text-2xl font-bold mb-6">Lançamento em {selectedBank.nome}</h2>
              <form onSubmit={handleCreateExpense} className="space-y-4">
                <input type="text" placeholder="Descrição" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.desc} onChange={e => setExpForm({...expForm, desc: e.target.value})} required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="text" placeholder="Valor (0,00)" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.val} onChange={e => setExpForm({...expForm, val: e.target.value})} required />
                  <input type="date" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.date} onChange={e => setExpForm({...expForm, date: e.target.value})} required />
                </div>
                <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setShowExpenseModal(false)} className="flex-1 bg-gray-100 py-3 rounded-xl font-bold">Cancelar</button>
                  <button type="submit" className="flex-1 bg-green-800 text-white py-3 rounded-xl font-bold">Lançar</button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold">Instituições Financeiras</h3>
        {currentMonth.status === 'ativo' && (
          <button 
            onClick={() => setShowBankModal(true)}
            className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
          >
            <Plus size={18} /> Novo Banco
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {banks.map(bank => (
          <button 
            key={bank.id}
            onClick={() => setSelectedBank(bank)}
            className="group relative bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 transition-all hover:shadow-xl hover:-translate-y-1 text-left overflow-hidden"
          >
            <div 
              className="absolute top-0 right-0 w-32 h-32 -mr-10 -mt-10 rounded-full opacity-10 group-hover:scale-125 transition-transform"
              style={{ backgroundColor: bank.cor }}
            ></div>
            <div 
              className="w-12 h-12 rounded-2xl flex items-center justify-center text-white mb-6 shadow-lg"
              style={{ backgroundColor: bank.cor }}
            >
              <Banknote size={24} />
            </div>
            <div className="flex justify-between items-end">
              <div>
                <h4 className="text-xl font-bold text-gray-800">{bank.nome}</h4>
                <p className="text-sm text-gray-400 font-medium">Gestão de Crédito</p>
              </div>
              <ChevronRight className="text-gray-300 group-hover:text-green-700 transition" />
            </div>
          </button>
        ))}
      </div>

      {showBankModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl">
            <h2 className="text-2xl font-bold mb-6">Nova Instituição</h2>
            <form onSubmit={handleCreateBank} className="space-y-4">
              <input type="text" placeholder="Nome do Banco" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={bankForm.nome} onChange={e => setBankForm({...bankForm, nome: e.target.value})} required />
              <div className="flex items-center gap-4">
                <label className="text-sm font-bold text-gray-600">Cor de Destaque</label>
                <input type="color" className="w-20 h-10 rounded cursor-pointer" value={bankForm.cor} onChange={e => setBankForm({...bankForm, cor: e.target.value})} />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowBankModal(false)} className="flex-1 bg-gray-100 py-3 rounded-xl font-bold">Cancelar</button>
                <button type="submit" className="flex-1 bg-green-800 text-white py-3 rounded-xl font-bold">Criar Banco</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Banks;

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  TrendingUp, 
  Banknote, 
  LockKeyhole, 
  Menu, 
  X,
  Wallet,
  User,
  RefreshCw
} from 'lucide-react';
import { supabaseClient } from './services/supabase';
import { Month } from './types';
import Overview from './components/Overview';
import Expenses from './components/Expenses';
import Revenue from './components/Revenue';
import Banks from './components/Banks';
import Closing from './components/Closing';

const App: React.FC = () => {
  const [view, setView] = useState<string>('overview');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [currentMonth, setCurrentMonth] = useState<Month | null>(null);
  const [activeMonth, setActiveMonth] = useState<Month | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshKey, setRefreshKey] = useState(0);

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    setLoading(true);
    try {
      const { data: meses } = await supabaseClient
        .from('meses')
        .select('*')
        .order('criado_em', { ascending: false });

      if (!meses || meses.length === 0) {
        const { data } = await supabaseClient
          .from('meses')
          .insert([{ nome: 'DEZEMBRO', ano: 2025, status: 'ativo' }])
          .select()
          .single();
        setCurrentMonth(data);
        setActiveMonth(data);
      } else {
        const active = meses.find((m: any) => m.status === 'ativo') || meses[0];
        setActiveMonth(active);
        setCurrentMonth(active);
      }
    } catch (error) {
      console.error("Initialization error:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleGlobalRefresh = () => {
    setRefreshKey(prev => prev + 1);
    init();
  };

  const handleNavigate = (newView: string) => {
    setView(newView);
    setIsSidebarOpen(false);
  };

  const handleMonthChange = (month: Month) => {
    setCurrentMonth(month);
  };

  if (loading || !currentMonth) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 animate-spin rounded-full border-4 border-green-700 border-t-transparent"></div>
          <p className="font-medium text-gray-600 animate-pulse">Recuperando dados do sistema...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden text-gray-900">
      {/* Mobile Menu Button */}
      <button 
        className="fixed top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md lg:hidden"
        onClick={() => setIsSidebarOpen(!isSidebarOpen)}
      >
        {isSidebarOpen ? <X /> : <Menu />}
      </button>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r border-gray-200 transform transition-transform duration-300 ease-in-out lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="flex flex-col h-full p-6">
          <div className="flex items-center gap-3 mb-10 text-green-800">
            <div className="bg-green-100 p-2 rounded-full">
              <Wallet size={24} />
            </div>
            <span className="text-xl font-bold">M&D Finanças</span>
          </div>

          <nav className="flex-1 space-y-1">
            <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-4 px-2">Menu Principal</p>
            <NavItem icon={<LayoutDashboard size={20} />} label="Visão Geral" active={view === 'overview'} onClick={() => handleNavigate('overview')} />
            <NavItem icon={<Receipt size={20} />} label="Despesas" active={view === 'expenses'} onClick={() => handleNavigate('expenses')} />
            <NavItem icon={<TrendingUp size={20} />} label="Receitas" active={view === 'revenue'} onClick={() => handleNavigate('revenue')} />
            <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mt-8 mb-4 px-2">Gestão</p>
            <NavItem icon={<Banknote size={20} />} label="Bancos" active={view === 'banks'} onClick={() => handleNavigate('banks')} />
            <NavItem icon={<LockKeyhole size={20} />} label="Histórico / Fechamento" active={view === 'closing'} onClick={() => handleNavigate('closing')} />
          </nav>

          <div className="mt-auto pt-6 border-t border-gray-100">
            <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-xl">
              <div className="bg-white p-2 rounded-full border border-gray-200">
                <User size={18} className="text-gray-600" />
              </div>
              <div className="flex flex-col">
                <span className="text-sm font-bold">M&D Admin</span>
                <span className="text-xs text-gray-500">Logado via Supabase</span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 lg:p-10 relative">
        <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
          <div>
            <h1 className="text-2xl lg:text-3xl font-bold text-gray-900">
              {view === 'overview' && 'Visão Geral'}
              {view === 'expenses' && 'Minhas Despesas'}
              {view === 'revenue' && 'Entradas e Receitas'}
              {view === 'banks' && 'Bancos e Instituições'}
              {view === 'closing' && 'Controle de Período'}
            </h1>
            <p className="text-gray-500">Ref: {currentMonth.nome} {currentMonth.ano}</p>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={handleGlobalRefresh}
              className="p-2.5 bg-white border border-gray-200 rounded-full text-gray-500 hover:text-green-700 hover:border-green-200 transition-all shadow-sm group"
              title="Sincronizar dados do banco"
            >
              <RefreshCw size={20} className="group-active:rotate-180 transition-transform duration-500" />
            </button>

            {currentMonth.status === 'fechado' && activeMonth && currentMonth.id !== activeMonth.id && (
              <button 
                onClick={() => setCurrentMonth(activeMonth)}
                className="px-4 py-2 text-sm font-medium bg-white border border-gray-300 rounded-full hover:bg-gray-50 transition shadow-sm"
              >
                Voltar ao Mês Atual
              </button>
            )}
            <div className={`px-4 py-2 rounded-full text-sm font-semibold shadow-sm ${
              currentMonth.status === 'ativo' ? 'bg-green-600 text-white' : 'bg-red-500 text-white'
            }`}>
              {currentMonth.status === 'ativo' ? 'Mês Ativo' : 'Mês Fechado'}
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'overview' && <Overview key={`ov-${refreshKey}`} currentMonth={currentMonth} refresh={handleGlobalRefresh} />}
          {view === 'expenses' && <Expenses key={`ex-${refreshKey}`} currentMonth={currentMonth} />}
          {view === 'revenue' && <Revenue key={`rv-${refreshKey}`} currentMonth={currentMonth} />}
          {view === 'banks' && <Banks key={`bk-${refreshKey}`} currentMonth={currentMonth} />}
          {view === 'closing' && <Closing key={`cl-${refreshKey}`} currentMonth={currentMonth} onSelectMonth={handleMonthChange} onRefresh={init} />}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 font-medium ${
      active 
        ? 'bg-green-700 text-white shadow-lg shadow-green-900/20' 
        : 'text-gray-500 hover:bg-gray-50 hover:text-green-700'
    }`}
  >
    {icon}
    <span>{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { TrendingDown, TrendingUp, Wallet, ArrowRight, History, CalendarDays } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month } from '../types';

interface OverviewProps {
  currentMonth: Month;
  refresh: () => void;
}

const Overview: React.FC<OverviewProps> = ({ currentMonth, refresh }) => {
  const [totals, setTotals] = useState({ revenue: 0, expenses: 0, balance: 0 });
  const [recentTransactions, setRecentTransactions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  const fetchData = async () => {
    setLoading(true);
    try {
      // Recuperar Totais
      const [receitasRes, despesasRes, pixRes, bancosRes] = await Promise.all([
        supabaseClient.from('receitas').select('valor, descricao, data, criado_em').eq('mes_id', currentMonth.id),
        supabaseClient.from('despesas_contas').select('valor, descricao, data, criado_em').eq('mes_id', currentMonth.id),
        supabaseClient.from('despesas_pix_credito').select('valor_final, descricao, data, criado_em').eq('mes_id', currentMonth.id),
        supabaseClient.from('banco_despesas').select('valor, descricao, data, criado_em').eq('mes_id', currentMonth.id)
      ]);

      const rev = receitasRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;
      const exp = (despesasRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0) +
                  (pixRes.data?.reduce((acc, curr) => acc + curr.valor_final, 0) || 0) +
                  (bancosRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0);

      setTotals({
        revenue: rev,
        expenses: exp,
        balance: rev - exp
      });

      // Recuperar Lançamentos Recentes (Unificando as tabelas para histórico)
      const allItems = [
        ...(receitasRes.data || []).map(i => ({ ...i, type: 'revenue' })),
        ...(despesasRes.data || []).map(i => ({ ...i, type: 'expense' })),
        ...(pixRes.data || []).map(i => ({ ...i, type: 'pix', valor: i.valor_final })),
        ...(bancosRes.data || []).map(i => ({ ...i, type: 'bank' }))
      ].sort((a, b) => new Date(b.criado_em || b.data).getTime() - new Date(a.criado_em || a.data).getTime());

      setRecentTransactions(allItems.slice(0, 5));
    } catch (err) {
      console.error("Erro ao recuperar dados:", err);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-20 text-gray-400 gap-4">
      <div className="h-10 w-10 border-4 border-green-700 border-t-transparent rounded-full animate-spin"></div>
      <p className="font-medium">Recuperando saldos do banco...</p>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-green-900 text-white p-8 rounded-[2rem] shadow-xl relative overflow-hidden group">
          <div className="absolute -right-4 -top-4 bg-white/10 p-12 rounded-full transition-transform group-hover:scale-110"></div>
          <p className="text-green-100/70 font-medium mb-1 flex items-center gap-2">
            <Wallet size={16} /> Saldo Líquido
          </p>
          <h2 className="text-4xl font-bold tracking-tight">{formatCurrency(totals.balance)}</h2>
          <p className="mt-4 text-sm text-green-100/50">Disponível no período de {currentMonth.nome}</p>
        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-green-100 p-3 rounded-2xl text-green-700">
              <TrendingUp size={24} />
            </div>
            <span className="text-xs font-bold text-green-600 bg-green-50 px-2 py-1 rounded-md">Entradas</span>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-sm font-medium">Total Receitas</p>
            <h2 className="text-2xl font-bold">{formatCurrency(totals.revenue)}</h2>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-red-100 p-3 rounded-2xl text-red-600">
              <TrendingDown size={24} />
            </div>
            <span className="text-xs font-bold text-red-600 bg-red-50 px-2 py-1 rounded-md">Saídas</span>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-sm font-medium">Total Despesas</p>
            <h2 className="text-2xl font-bold">{formatCurrency(totals.expenses)}</h2>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Lançamentos Recentes */}
        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold flex items-center gap-2">
              <History className="text-gray-400" size={20} />
              Recuperados Recentemente
            </h3>
            <span className="text-xs font-bold text-gray-400 uppercase">Últimos 5</span>
          </div>
          <div className="space-y-3">
            {recentTransactions.length === 0 ? (
              <p className="text-center py-10 text-gray-400">Nenhum lançamento encontrado.</p>
            ) : (
              recentTransactions.map((item, idx) => (
                <div key={idx} className="flex items-center justify-between p-3 rounded-xl bg-gray-50/50 border border-gray-100">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg ${item.type === 'revenue' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                      {item.type === 'revenue' ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                    </div>
                    <div>
                      <p className="text-sm font-bold text-gray-800">{item.descricao}</p>
                      <p className="text-[10px] text-gray-400 uppercase font-bold">{new Date(item.data).toLocaleDateString('pt-BR')}</p>
                    </div>
                  </div>
                  <span className={`text-sm font-bold ${item.type === 'revenue' ? 'text-green-700' : 'text-red-700'}`}>
                    {item.type === 'revenue' ? '+' : '-'} {formatCurrency(item.valor)}
                  </span>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Info Extra */}
        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 flex flex-col">
          <h3 className="text-lg font-bold mb-6 flex items-center gap-2">
            <CalendarDays size={20} className="text-gray-400" />
            Informações do Período
          </h3>
          <div className="flex-1 flex flex-col justify-center space-y-4">
            <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl">
              <p className="text-xs font-bold text-blue-800 uppercase mb-1">Status da Base</p>
              <p className="text-sm text-blue-900/70">O sistema está conectado ao banco de dados em tempo real. Todas as alterações são salvas automaticamente.</p>
            </div>
            <button 
              onClick={refresh}
              className="w-full flex items-center justify-center gap-2 bg-gray-900 text-white font-bold py-4 rounded-2xl hover:bg-black transition shadow-lg shadow-gray-900/20"
            >
              Forçar Recarregamento Total
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Overview;

import React, { useState, useEffect } from 'react';
import { Banknote, Plus, ChevronRight, ArrowLeft, Trash2, CheckCircle2, Circle, Save, Info } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Bank, BankExpense } from '../types';

interface BanksProps {
  currentMonth: Month;
}

const Banks: React.FC<BanksProps> = ({ currentMonth }) => {
  const [banks, setBanks] = useState<Bank[]>([]);
  const [selectedBank, setSelectedBank] = useState<Bank | null>(null);
  const [bankExpenses, setBankExpenses] = useState<BankExpense[]>([]);
  const [loading, setLoading] = useState(true);

  // Custom states for special banks
  const [specialFields, setSpecialFields] = useState<{ [key: string]: string }>({});
  const [saving, setSaving] = useState(false);

  const [showBankModal, setShowBankModal] = useState(false);
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [bankForm, setBankForm] = useState({ nome: '', cor: '#15803d' });
  const [expForm, setExpForm] = useState({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchBanks();
  }, []);

  useEffect(() => {
    if (selectedBank) {
      fetchBankExpenses();
    }
  }, [selectedBank, currentMonth]);

  const fetchBanks = async () => {
    const { data } = await supabaseClient.from('bancos').select('*');
    setBanks(data || []);
    setLoading(false);
  };

  const fetchBankExpenses = async () => {
    if (!selectedBank) return;
    const { data } = await supabaseClient
      .from('banco_despesas')
      .select('*')
      .eq('banco_id', selectedBank.id)
      .eq('mes_id', currentMonth.id)
      .order('data', { ascending: true });

    setBankExpenses(data || []);

    // Load special fields if AMEX or BB
    if (selectedBank.nome === 'American Express' || selectedBank.nome === 'BB') {
      const initialFields: { [key: string]: string } = {};
      const fields = selectedBank.nome === 'American Express' 
        ? ['Compras à Vista', 'Em Processamento'] 
        : ['Compras à Vista', 'Em Processamento', 'Parceladas'];

      fields.forEach(f => {
        const found = data?.find(d => d.descricao === f);
        // Recuperar valor existente ou deixar em branco
        initialFields[f] = found ? found.valor.toFixed(2).replace('.', ',') : '';
      });
      setSpecialFields(initialFields);
    }
  };

  const handleSaveSpecial = async () => {
    if (!selectedBank) return;
    setSaving(true);
    try {
      const fields = Object.keys(specialFields);
      for (const field of fields) {
        const rawVal = specialFields[field].replace(',', '.');
        const val = parseFloat(rawVal) || 0;

        const existing = bankExpenses.find(e => e.descricao === field);

        if (existing) {
          await supabaseClient.from('banco_despesas').update({ valor: val }).eq('id', existing.id);
        } else {
          await supabaseClient.from('banco_despesas').insert([{
            mes_id: currentMonth.id,
            banco_id: selectedBank.id,
            descricao: field,
            valor: val,
            pago: true, // Lançamentos fixos de banco consideramos como consolidados
            data: new Date().toISOString().split('T')[0]
          }]);
        }
      }
      alert("Recuperação e salvamento concluídos!");
      fetchBankExpenses();
    } catch (error) {
      console.error(error);
      alert("Erro ao salvar dados.");
    } finally {
      setSaving(false);
    }
  };

  const handleCreateBank = async (e: React.FormEvent) => {
    e.preventDefault();
    await supabaseClient.from('bancos').insert([bankForm]);
    setShowBankModal(false);
    setBankForm({ nome: '', cor: '#15803d' });
    fetchBanks();
  };

  const handleCreateExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBank) return;
    const val = parseFloat(expForm.val.replace(',', '.'));
    await supabaseClient.from('banco_despesas').insert([{
      mes_id: currentMonth.id,
      banco_id: selectedBank.id,
      descricao: expForm.desc,
      valor: val,
      data: expForm.date
    }]);
    setShowExpenseModal(false);
    setExpForm({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });
    fetchBankExpenses();
  };

  const handleTogglePaid = async (id: number, current: boolean) => {
    if (currentMonth.status === 'fechado') return;
    await supabaseClient.from('banco_despesas').update({ pago: !current }).eq('id', id);
    fetchBankExpenses();
  };

  const handleDeleteExpense = async (id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Remover despesa?")) return;
    await supabaseClient.from('banco_despesas').delete().eq('id', id);
    fetchBankExpenses();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (selectedBank) {
    const total = bankExpenses.reduce((acc, curr) => acc + curr.valor, 0);
    const isSpecial = selectedBank.nome === 'American Express' || selectedBank.nome === 'BB';

    return (
      <div className="space-y-6 animate-in slide-in-from-right duration-300">
        <button 
          onClick={() => setSelectedBank(null)}
          className="flex items-center gap-2 text-gray-500 hover:text-gray-900 transition font-medium"
        >
          <ArrowLeft size={18} /> Voltar para Bancos
        </button>

        <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
          <div className="flex justify-between items-center mb-8">
            <div className="flex items-center gap-4">
              <div 
                className="w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-inner" 
                style={{ backgroundColor: selectedBank.cor }}
              >
                <Banknote size={24} />
              </div>
              <div>
                <h3 className="text-2xl font-bold">{selectedBank.nome}</h3>
                <p className="text-sm text-gray-500 font-medium">Total Recuperado: {formatCurrency(total)}</p>
              </div>
            </div>
            {!isSpecial && currentMonth.status === 'ativo' && (
              <button 
                onClick={() => setShowExpenseModal(true)}
                className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
              >
                <Plus size={18} /> Novo Lançamento
              </button>
            )}
          </div>

          {isSpecial ? (
            <div className="max-w-xl mx-auto space-y-6 bg-gray-50 p-8 rounded-3xl border border-gray-100">
              <div className="flex items-center gap-2 text-blue-600 mb-4 bg-blue-50 p-3 rounded-xl border border-blue-100">
                <Info size={18} />
                <span className="text-xs font-bold">Gerencie os valores fixos do cartão. O sistema somará todos automaticamente.</span>
              </div>

              <div className="space-y-4">
                {Object.keys(specialFields).map(f => (
                  <div key={f}>
                    <label className="block text-sm font-bold text-gray-700 mb-1">{f}</label>
                    <input 
                      type="text"
                      value={specialFields[f]}
                      onChange={e => setSpecialFields({...specialFields, [f]: e.target.value})}
                      placeholder="0,00"
                      className="w-full bg-white border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700 font-bold text-lg"
                      disabled={currentMonth.status === 'fechado'}
                    />
                  </div>
                ))}
              </div>

              {currentMonth.status === 'ativo' && (
                <button 
                  onClick={handleSaveSpecial}
                  disabled={saving}
                  className="w-full bg-green-800 text-white font-bold py-4 rounded-2xl shadow-lg shadow-green-900/20 hover:bg-green-900 transition flex items-center justify-center gap-2"
                >
                  {saving ? <div className="h-5 w-5 animate-spin rounded-full border-2 border-white border-t-transparent" /> : <Save size={20} />}
                  Salvar e Atualizar
                </button>
              )}
            </div>
          ) : (
            <div className="space-y-2">
              {bankExpenses.length === 0 ? <p className="text-center py-20 text-gray-400">Nenhum gasto neste banco.</p> :
              bankExpenses.map(exp => (
                <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100 hover:border-green-200'}`}>
                  <div className="flex items-center gap-4">
                    <button onClick={() => handleTogglePaid(exp.id, exp.pago)} className={`${exp.pago ? 'text-green-600' : 'text-gray-300'}`}>
                      {exp.pago ? <CheckCircle2 /> : <Circle />}
                    </button>
                    <div>
                      <h4 className={`font-bold ${exp.pago ? 'line-through text-gray-400' : ''}`}>{exp.descricao}</h4>
                      <p className="text-xs text-gray-400 font-medium uppercase">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-6">
                    <span className="font-bold text-lg">{formatCurrency(exp.valor)}</span>
                    {currentMonth.status === 'ativo' && (
                      <button onClick={() => handleDeleteExpense(exp.id)} className="text-gray-300 hover:text-red-500 transition">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {showExpenseModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl">
              <h2 className="text-2xl font-bold mb-6">Lançamento em {selectedBank.nome}</h2>
              <form onSubmit={handleCreateExpense} className="space-y-4">
                <input type="text" placeholder="Descrição" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.desc} onChange={e => setExpForm({...expForm, desc: e.target.value})} required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="text" placeholder="Valor (0,00)" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.val} onChange={e => setExpForm({...expForm, val: e.target.value})} required />
                  <input type="date" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={expForm.date} onChange={e => setExpForm({...expForm, date: e.target.value})} required />
                </div>
                <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setShowExpenseModal(false)} className="flex-1 bg-gray-100 py-3 rounded-xl font-bold">Cancelar</button>
                  <button type="submit" className="flex-1 bg-green-800 text-white py-3 rounded-xl font-bold">Lançar</button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold">Instituições Financeiras</h3>
        {currentMonth.status === 'ativo' && (
          <button 
            onClick={() => setShowBankModal(true)}
            className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
          >
            <Plus size={18} /> Novo Banco
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {banks.map(bank => (
          <button 
            key={bank.id}
            onClick={() => setSelectedBank(bank)}
            className="group relative bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 transition-all hover:shadow-xl hover:-translate-y-1 text-left overflow-hidden"
          >
            <div 
              className="absolute top-0 right-0 w-32 h-32 -mr-10 -mt-10 rounded-full opacity-10 group-hover:scale-125 transition-transform"
              style={{ backgroundColor: bank.cor }}
            ></div>
            <div 
              className="w-12 h-12 rounded-2xl flex items-center justify-center text-white mb-6 shadow-lg"
              style={{ backgroundColor: bank.cor }}
            >
              <Banknote size={24} />
            </div>
            <div className="flex justify-between items-end">
              <div>
                <h4 className="text-xl font-bold text-gray-800">{bank.nome}</h4>
                <p className="text-sm text-gray-400 font-medium">Gestão de Crédito</p>
              </div>
              <ChevronRight className="text-gray-300 group-hover:text-green-700 transition" />
            </div>
          </button>
        ))}
      </div>

      {showBankModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl">
            <h2 className="text-2xl font-bold mb-6">Nova Instituição</h2>
            <form onSubmit={handleCreateBank} className="space-y-4">
              <input type="text" placeholder="Nome do Banco" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none" value={bankForm.nome} onChange={e => setBankForm({...bankForm, nome: e.target.value})} required />
              <div className="flex items-center gap-4">
                <label className="text-sm font-bold text-gray-600">Cor de Destaque</label>
                <input type="color" className="w-20 h-10 rounded cursor-pointer" value={bankForm.cor} onChange={e => setBankForm({...bankForm, cor: e.target.value})} />
              </div>
