                  {saving ? <div className="h-6 w-6 animate-spin rounded-full border-3 border-white border-t-transparent" /> : <Save size={24} />}
                  Salvar {selectedBank.nome}
                </button>
              )}
            </div>
          ) : (
            <div className="space-y-2">
              {bankExpenses.length === 0 ? <p className="text-center py-20 text-gray-400">Nenhum gasto neste banco.</p> :
              bankExpenses.map(exp => (
                <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100 hover:border-green-200 transition'}`}>
                  <div className="flex items-center gap-4">
                    <button onClick={() => handleTogglePaid(exp.id, exp.pago)} className={`${exp.pago ? 'text-green-600' : 'text-gray-300 hover:text-green-400'}`}>
                      {exp.pago ? <CheckCircle2 /> : <Circle />}
                    </button>
                    <div>
                      <h4 className={`font-bold ${exp.pago ? 'line-through text-gray-400' : ''}`}>{exp.descricao}</h4>
                      <p className="text-xs text-gray-400 font-medium uppercase">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-6">
                    <span className="font-bold text-lg">{formatCurrency(exp.valor)}</span>
                    {currentMonth.status === 'ativo' && (
                      <button onClick={() => handleDeleteExpense(exp.id)} className="text-gray-300 hover:text-red-500 transition">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {showExpenseModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl animate-in fade-in zoom-in duration-200">
              <h2 className="text-2xl font-bold mb-6">Lançamento em {selectedBank.nome}</h2>
              <form onSubmit={handleCreateExpense} className="space-y-4">
                <input type="text" placeholder="Descrição" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={expForm.desc} onChange={e => setExpForm({...expForm, desc: e.target.value})} required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="text" placeholder="Valor (0,00)" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={expForm.val} onChange={e => setExpForm({...expForm, val: e.target.value})} required />
                  <input type="date" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={expForm.date} onChange={e => setExpForm({...expForm, date: e.target.value})} required />
                </div>
                <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setShowExpenseModal(false)} className="flex-1 bg-gray-100 py-3 rounded-xl font-bold text-gray-500">Cancelar</button>
                  <button type="submit" className="flex-1 bg-green-800 text-white py-3 rounded-xl font-bold shadow-lg shadow-green-900/20">Lançar</button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold">Instituições Financeiras</h3>
        {currentMonth.status === 'ativo' && (
          <button 
            onClick={() => setShowBankModal(true)}
            className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2 hover:bg-green-900 transition shadow-lg shadow-green-900/20"
          >
            <Plus size={18} /> Novo Banco
