export default Banks;

import React, { useState, useEffect } from 'react';
import { Banknote, Plus, ChevronRight, ArrowLeft, Trash2, CheckCircle2, Circle, Save, Info } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Bank, BankExpense } from '../types';

interface BanksProps {
  currentMonth: Month;
}

const Banks: React.FC<BanksProps> = ({ currentMonth }) => {
  const [banks, setBanks] = useState<Bank[]>([]);
  const [selectedBank, setSelectedBank] = useState<Bank | null>(null);
  const [bankExpenses, setBankExpenses] = useState<BankExpense[]>([]);
  const [loading, setLoading] = useState(true);

  const [specialFields, setSpecialFields] = useState<{ [key: string]: string }>({});
  const [saving, setSaving] = useState(false);

  const [showBankModal, setShowBankModal] = useState(false);
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [bankForm, setBankForm] = useState({ nome: '', cor: '#15803d' });
  const [expForm, setExpForm] = useState({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchBanks();
  }, []);

  useEffect(() => {
    if (selectedBank) {
      fetchBankExpenses();
    }
  }, [selectedBank, currentMonth]);

  const fetchBanks = async () => {
    const { data } = await supabaseClient.from('bancos').select('*').order('nome');
    setBanks(data || []);
    setLoading(false);
  };

  const fetchBankExpenses = async () => {
    if (!selectedBank) return;
    const { data } = await supabaseClient
      .from('banco_despesas')
      .select('*')
      .eq('banco_id', selectedBank.id)
      .eq('mes_id', currentMonth.id)
      .order('data', { ascending: true });

    setBankExpenses(data || []);

    if (selectedBank.nome === 'American Express' || selectedBank.nome === 'BB') {
      const initialFields: { [key: string]: string } = {};
      const fields = selectedBank.nome === 'American Express' 
        ? ['Compras à Vista', 'Em Processamento'] 
        : ['Compras à Vista', 'Em Processamento', 'Parceladas'];

      fields.forEach(f => {
        const found = data?.find(d => d.descricao === f);
        initialFields[f] = found ? found.valor.toFixed(2).replace('.', ',') : '0,00';
      });
      setSpecialFields(initialFields);
    }
  };

  const handleSaveSpecial = async () => {
    if (!selectedBank) return;
    setSaving(true);
    try {
      const fields = Object.keys(specialFields);
      for (const field of fields) {
        const rawVal = specialFields[field].replace(',', '.');
        const val = parseFloat(rawVal) || 0;

        const existing = bankExpenses.find(e => e.descricao === field);

        if (existing) {
          await supabaseClient.from('banco_despesas').update({ valor: val }).eq('id', existing.id);
        } else {
          await supabaseClient.from('banco_despesas').insert([{
            mes_id: currentMonth.id,
            banco_id: selectedBank.id,
            descricao: field,
            valor: val,
            pago: true,
            data: new Date().toISOString().split('T')[0]
          }]);
        }
      }
      alert("Valores de " + selectedBank.nome + " atualizados com sucesso!");
      fetchBankExpenses();
    } catch (error) {
      console.error(error);
      alert("Erro ao salvar dados.");
    } finally {
      setSaving(false);
    }
  };

  const handleCreateBank = async (e: React.FormEvent) => {
    e.preventDefault();
    await supabaseClient.from('bancos').insert([bankForm]);
    setShowBankModal(false);
    setBankForm({ nome: '', cor: '#15803d' });
    fetchBanks();
  };

  const handleDeleteBank = async (e: React.MouseEvent, id: number, name: string) => {
    e.preventDefault();
    e.stopPropagation();

    if (currentMonth.status === 'fechado') {
      alert("Não é possível excluir bancos com o mês fechado.");
      return;
    }

    if (!confirm(`Deseja realmente excluir o banco ${name}?\n\nISSO APAGARÁ TODOS OS GASTOS DESTE BANCO EM TODOS OS MESES!`)) return;

    try {
      const { error } = await supabaseClient.from('bancos').delete().eq('id', id);
      if (error) throw error;

      // Feedback visual imediato removendo da lista local
      setBanks(prev => prev.filter(b => b.id !== id));
      alert(`Banco ${name} removido com sucesso.`);
    } catch (error: any) {
      console.error("Erro ao deletar banco:", error);
      alert("Erro ao excluir banco: " + (error.message || "Verifique as permissões."));
    }
  };

  const handleCreateExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBank) return;
    const val = parseFloat(expForm.val.replace(',', '.'));
    await supabaseClient.from('banco_despesas').insert([{
      mes_id: currentMonth.id,
      banco_id: selectedBank.id,
      descricao: expForm.desc,
      valor: val,
      data: expForm.date
    }]);
    setShowExpenseModal(false);
    setExpForm({ desc: '', val: '', date: new Date().toISOString().split('T')[0] });
    fetchBankExpenses();
  };

  const handleTogglePaid = async (id: number, current: boolean) => {
    if (currentMonth.status === 'fechado') return;
    await supabaseClient.from('banco_despesas').update({ pago: !current }).eq('id', id);
    fetchBankExpenses();
  };

  const handleDeleteExpense = async (id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Remover despesa?")) return;
    await supabaseClient.from('banco_despesas').delete().eq('id', id);
    fetchBankExpenses();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (selectedBank) {
    const total = bankExpenses.reduce((acc, curr) => acc + curr.valor, 0);
    const isSpecial = selectedBank.nome === 'American Express' || selectedBank.nome === 'BB';

    return (
      <div className="space-y-6 animate-in slide-in-from-right duration-300">
        <button 
          onClick={() => setSelectedBank(null)}
          className="flex items-center gap-2 text-gray-500 hover:text-gray-900 transition font-medium"
        >
          <ArrowLeft size={18} /> Voltar para Bancos
        </button>

        <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
          <div className="flex justify-between items-center mb-8">
            <div className="flex items-center gap-4">
              <div 
                className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg transition-transform hover:scale-105`}
                style={{ backgroundColor: selectedBank.cor, color: selectedBank.nome === 'BB' ? '#003366' : 'white' }}
              >
                <Banknote size={28} />
              </div>
              <div>
                <h3 className="text-2xl font-bold">{selectedBank.nome}</h3>
                <p className="text-sm text-gray-500 font-medium">Total do Cartão: {formatCurrency(total)}</p>
              </div>
            </div>
            {!isSpecial && currentMonth.status === 'ativo' && (
              <button 
                onClick={() => setShowExpenseModal(true)}
                className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
              >
                <Plus size={18} /> Novo Lançamento
              </button>
            )}
          </div>

          {isSpecial ? (
            <div className="max-w-xl mx-auto space-y-6 bg-gray-50 p-8 rounded-[2.5rem] border border-gray-100 shadow-inner">
              <div className="flex items-center gap-2 text-blue-700 mb-4 bg-blue-50/50 p-4 rounded-2xl border border-blue-100">
                <Info size={20} className="shrink-0" />
                <span className="text-xs font-bold leading-tight">Os campos abaixo são sincronizados diretamente com o banco de dados para este mês.</span>
              </div>

              <div className="space-y-5">
                {Object.keys(specialFields).map(f => (
                  <div key={f} className="group">
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-1 ml-1 group-focus-within:text-green-700 transition">{f}</label>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">R$</span>
                      <input 
                        type="text"
                        value={specialFields[f]}
                        onChange={e => setSpecialFields({...specialFields, [f]: e.target.value})}
                        placeholder="0,00"
                        className="w-full bg-white border border-gray-200 rounded-2xl pl-10 pr-4 py-4 outline-none focus:ring-4 focus:ring-green-700/10 focus:border-green-700 font-black text-xl text-gray-800 transition shadow-sm"
                        disabled={currentMonth.status === 'fechado'}
                      />
                    </div>
                  </div>
                ))}
              </div>

              {currentMonth.status === 'ativo' && (
                <button 
                  onClick={handleSaveSpecial}
                  disabled={saving}
                  className="w-full bg-green-800 text-white font-black py-5 rounded-2xl shadow-xl shadow-green-900/20 hover:bg-green-900 active:scale-95 transition flex items-center justify-center gap-3 mt-8"
                >
                  {saving ? <div className="h-6 w-6 animate-spin rounded-full border-3 border-white border-t-transparent" /> : <Save size={24} />}
                  Salvar {selectedBank.nome}
                </button>
              )}
            </div>
          ) : (
            <div className="space-y-2">
              {bankExpenses.length === 0 ? <p className="text-center py-20 text-gray-400">Nenhum gasto neste banco.</p> :
              bankExpenses.map(exp => (
                <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100 hover:border-green-200 transition'}`}>
                  <div className="flex items-center gap-4">
                    <button onClick={() => handleTogglePaid(exp.id, exp.pago)} className={`${exp.pago ? 'text-green-600' : 'text-gray-300 hover:text-green-400'}`}>
                      {exp.pago ? <CheckCircle2 /> : <Circle />}
                    </button>
                    <div>
                      <h4 className={`font-bold ${exp.pago ? 'line-through text-gray-400' : ''}`}>{exp.descricao}</h4>
                      <p className="text-xs text-gray-400 font-medium uppercase">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-6">
                    <span className="font-bold text-lg">{formatCurrency(exp.valor)}</span>
                    {currentMonth.status === 'ativo' && (
                      <button onClick={() => handleDeleteExpense(exp.id)} className="text-gray-300 hover:text-red-500 transition">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {showExpenseModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl animate-in fade-in zoom-in duration-200">
              <h2 className="text-2xl font-bold mb-6">Lançamento em {selectedBank.nome}</h2>
              <form onSubmit={handleCreateExpense} className="space-y-4">
                <input type="text" placeholder="Descrição" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={expForm.desc} onChange={e => setExpForm({...expForm, desc: e.target.value})} required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="text" placeholder="Valor (0,00)" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={expForm.val} onChange={e => setExpForm({...expForm, val: e.target.value})} required />
                  <input type="date" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={expForm.date} onChange={e => setExpForm({...expForm, date: e.target.value})} required />
                </div>
                <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setShowExpenseModal(false)} className="flex-1 bg-gray-100 py-3 rounded-xl font-bold text-gray-500">Cancelar</button>
                  <button type="submit" className="flex-1 bg-green-800 text-white py-3 rounded-xl font-bold shadow-lg shadow-green-900/20">Lançar</button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold">Instituições Financeiras</h3>
        {currentMonth.status === 'ativo' && (
          <button 
            onClick={() => setShowBankModal(true)}
            className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2 hover:bg-green-900 transition shadow-lg shadow-green-900/20"
          >
            <Plus size={18} /> Novo Banco
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {banks.map(bank => (
          <div key={bank.id} className="relative group">
            {/* O Botão principal que abre o banco */}
            <button 
              onClick={() => setSelectedBank(bank)}
              className="w-full bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 transition-all hover:shadow-2xl hover:-translate-y-2 text-left overflow-hidden relative"
            >
              <div 
                className="absolute top-0 right-0 w-32 h-32 -mr-10 -mt-10 rounded-full opacity-10 group-hover:scale-150 transition-transform duration-500"
                style={{ backgroundColor: bank.cor }}
              ></div>

              <div 
                className="w-14 h-14 rounded-2xl flex items-center justify-center mb-6 shadow-lg group-hover:rotate-6 transition-transform"
                style={{ backgroundColor: bank.cor, color: bank.nome === 'BB' ? '#003366' : 'white' }}
              >
                <Banknote size={28} />
              </div>

              <div className="flex justify-between items-end relative z-10">
                <div>
                  <h4 className="text-xl font-black text-gray-800">{bank.nome}</h4>
                  <p className="text-sm text-gray-400 font-bold uppercase tracking-widest text-[10px]">Gestão de Crédito</p>
                </div>
                <div className="bg-gray-50 p-2 rounded-full group-hover:bg-green-50 group-hover:text-green-700 transition-colors">
                  <ChevronRight size={20} />
                </div>
              </div>
            </button>

            {/* Botão de Excluir Banco (Sempre visível para evitar problemas de hover) */}
            {currentMonth.status === 'ativo' && (
              <button 
                onClick={(e) => handleDeleteBank(e, bank.id, bank.nome)}
                className="absolute top-6 right-6 z-30 p-2.5 bg-red-50 text-red-400 hover:text-red-700 hover:bg-red-100 rounded-full transition-all shadow-sm border border-red-100"
                title="Excluir Banco"
              >
                <Trash2 size={18} />
              </button>
            )}
          </div>
        ))}
      </div>

      {showBankModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl animate-in fade-in zoom-in duration-200">
            <h2 className="text-2xl font-bold mb-6">Nova Instituição</h2>
            <form onSubmit={handleCreateBank} className="space-y-4">
              <input type="text" placeholder="Nome do Banco" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={bankForm.nome} onChange={e => setBankForm({...bankForm, nome: e.target.value})} required />
