    return (
      <div className="space-y-6 animate-in slide-in-from-right duration-300">
        <button 
          onClick={() => setSelectedBank(null)}
          className="flex items-center gap-2 text-gray-500 hover:text-gray-900 transition font-medium"
        >
          <ArrowLeft size={18} /> Voltar para Bancos
        </button>

        <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
          <div className="flex justify-between items-center mb-8">
            <div className="flex items-center gap-4">
              <div 
                className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg transition-transform hover:scale-105`}
                style={{ backgroundColor: selectedBank.cor, color: selectedBank.nome === 'BB' ? '#003366' : 'white' }}
              >
                <Banknote size={28} />
              </div>
              <div>
                <h3 className="text-2xl font-bold">{selectedBank.nome}</h3>
                <p className="text-sm text-gray-500 font-medium">Total do Cartão: {formatCurrency(total)}</p>
              </div>
            </div>
            {!isSpecial && currentMonth.status === 'ativo' && (
              <button 
                onClick={() => setShowExpenseModal(true)}
                className="bg-green-800 text-white px-5 py-2.5 rounded-full font-bold text-sm flex items-center gap-2"
              >
                <Plus size={18} /> Novo Lançamento
              </button>
            )}
          </div>

          {isSpecial ? (
            <div className="max-w-xl mx-auto space-y-6 bg-gray-50 p-8 rounded-[2.5rem] border border-gray-100 shadow-inner">
              <div className="flex items-center gap-2 text-blue-700 mb-4 bg-blue-50/50 p-4 rounded-2xl border border-blue-100">
                <Info size={20} className="shrink-0" />
                <span className="text-xs font-bold leading-tight">Os campos abaixo são sincronizados diretamente com o banco de dados para este mês.</span>
              </div>

              <div className="space-y-5">
                {Object.keys(specialFields).map(f => (
                  <div key={f} className="group">
