                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">R$</span>
                      <input 
                        type="text"
                        value={specialFields[f]}
                        onChange={e => setSpecialFields({...specialFields, [f]: e.target.value})}
                        placeholder="0,00"
                        className="w-full bg-white border border-gray-200 rounded-2xl pl-10 pr-4 py-4 outline-none focus:ring-4 focus:ring-green-700/10 focus:border-green-700 font-black text-xl text-gray-800 transition shadow-sm"
                        disabled={currentMonth.status === 'fechado'}
                      />
                    </div>
                  </div>
                ))}
              </div>

              {currentMonth.status === 'ativo' && (
                <button 
                  onClick={handleSaveSpecial}
                  disabled={saving}
                  className="w-full bg-green-800 text-white font-black py-5 rounded-2xl shadow-xl shadow-green-900/20 hover:bg-green-900 active:scale-95 transition flex items-center justify-center gap-3 mt-8"
                >
                  {saving ? <div className="h-6 w-6 animate-spin rounded-full border-3 border-white border-t-transparent" /> : <Save size={24} />}
                  Salvar {selectedBank.nome}
                </button>
              )}
            </div>
          ) : (
            <div className="space-y-2">
              {bankExpenses.length === 0 ? <p className="text-center py-20 text-gray-400">Nenhum gasto neste banco.</p> :
              bankExpenses.map(exp => (
                <div key={exp.id} className={`flex items-center justify-between p-4 rounded-2xl border ${exp.pago ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-gray-100 hover:border-green-200 transition'}`}>
