                  </div>
                  <div className="flex items-center gap-6">
                    <span className="font-bold text-lg">{formatCurrency(exp.valor)}</span>
                    {currentMonth.status === 'ativo' && (
                      <button onClick={() => handleDeleteExpense(exp.id)} className="text-gray-300 hover:text-red-500 transition">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
