                  <ChevronRight size={20} />
                </div>
              </div>
            </div>

            {/* Botão de Excluir Banco (Camada separada) */}
            {currentMonth.status === 'ativo' && (
              <button 
                onClick={(e) => {
                  e.stopPropagation();
                  handleDeleteBank(bank.id, bank.nome);
                }}
                className="absolute top-4 right-4 z-20 p-3 bg-white text-gray-300 hover:text-red-600 hover:bg-red-50 rounded-full transition-all shadow-md border border-gray-100 opacity-0 group-hover:opacity-100"
                title="Excluir Banco"
              >
                <Trash2 size={20} />
              </button>
            )}
          </div>
        ))}
      </div>

      {showBankModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md p-8 rounded-[2rem] shadow-2xl animate-in fade-in zoom-in duration-200">
