            <form onSubmit={handleCreateBank} className="space-y-4">
              <input type="text" placeholder="Nome do Banco" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-green-700" value={bankForm.nome} onChange={e => setBankForm({...bankForm, nome: e.target.value})} required />
