import React, { useState, useEffect } from 'react';
import { CalendarClock, Plus, Trash2, X as LucideX, Info, Wallet } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Installment } from '../types';

interface InstallmentsProps {
  currentMonth: Month;
}

const Installments: React.FC<InstallmentsProps> = ({ currentMonth }) => {
  const [installments, setInstallments] = useState<Installment[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({
    desc: '',
    val: 'R$ 0,00',
    atual: '1',
    restante: '0'
  });

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabaseClient
      .from('parcelamentos')
      .select('*')
      .eq('mes_id', currentMonth.id)
      .order('criado_em', { ascending: false });
    setInstallments(data || []);
    setLoading(false);
  };

  const maskCurrency = (value: string) => {
    const digits = value.replace(/\D/g, "");
    const amount = Number(digits) / 100;
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(amount);
  };

  const parseCurrency = (value: string) => {
    return parseFloat(value.replace(/[^\d,]/g, '').replace(',', '.')) || 0;
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseCurrency(formData.val);
    const atual = parseInt(formData.atual);
    const restante = parseInt(formData.restante);

    if (!formData.desc || val <= 0) return;

    await supabaseClient.from('parcelamentos').insert([{
      mes_id: currentMonth.id,
      descricao: formData.desc,
      valor_parcela: val,
      parcela_atual: atual,
      parcelas_restantes: restante
    }]);

    setShowModal(false);
    setFormData({ desc: '', val: 'R$ 0,00', atual: '1', restante: '0' });
    fetchData();
  };

  const handleDelete = async (id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Remover este parcelamento?")) return;
    await supabaseClient.from('parcelamentos').delete().eq('id', id);
    fetchData();
  };

  return (
    <div className="space-y-6 pb-10">
      {/* Botão Adicionar - Largura Total */}
      {currentMonth.status === 'ativo' && (
        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-green-700 hover:bg-green-800 text-white font-black py-6 rounded-[2rem] shadow-xl shadow-green-900/20 active:scale-[0.99] transition-all flex items-center justify-center gap-3 uppercase tracking-[0.2em] text-sm"
        >
          <Plus size={24} />
          Adicionar Parcelamento
        </button>
      )}

      {loading ? (
        <div className="py-20 flex flex-col items-center gap-4 text-gray-400">
          <div className="w-10 h-10 border-4 border-green-700 border-t-transparent rounded-full animate-spin"></div>
          <p className="font-bold uppercase tracking-widest text-[10px]">Buscando dados...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {installments.length === 0 ? (
            <div className="col-span-full py-20 bg-white rounded-[2.5rem] border border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400">
              <CalendarClock size={48} className="mb-4 opacity-20" />
              <p className="font-bold uppercase tracking-widest text-xs">Nenhum parcelamento ativo</p>
            </div>
          ) : (
            installments.map(item => {
              const totalQuitacao = item.valor_parcela * (item.parcelas_restantes + 1);
              return (
                <div key={item.id} className="bg-white rounded-[2.5rem] p-8 border border-gray-100 shadow-sm hover:shadow-xl transition-all group relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-gray-50 -mr-10 -mt-10 rounded-full group-hover:scale-150 transition-transform duration-700"></div>

                  <div className="relative z-10">
                    <div className="flex justify-between items-start mb-6">
                      <div className="flex items-center gap-4">
                        <div className="bg-blue-50 p-4 rounded-2xl text-blue-600">
                          <CalendarClock size={24} />
                        </div>
                        <div>
                          <h4 className="font-black text-gray-900 text-xl">{item.descricao}</h4>
                          <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Contrato de Parcelas</p>
                        </div>
                      </div>
                      {currentMonth.status === 'ativo' && (
                        <button 
                          onClick={() => handleDelete(item.id)}
                          className="text-gray-200 hover:text-red-500 transition p-2"
                        >
                          <Trash2 size={20} />
                        </button>
                      )}
                    </div>

                    <div className="grid grid-cols-2 gap-4 mb-8">
                      <div className="bg-gray-50 p-5 rounded-3xl border border-gray-100">
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Valor Parcela</p>
                        <p className="text-xl font-black text-gray-900">{formatCurrency(item.valor_parcela)}</p>
                      </div>
                      <div className="bg-gray-50 p-5 rounded-3xl border border-gray-100">
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Status</p>
                        <p className="text-xl font-black text-gray-900">
                          {item.parcela_atual} <span className="text-gray-300 mx-1">|</span> {item.parcelas_restantes}
                          <span className="text-[10px] text-gray-400 ml-2">rest.</span>
                        </p>
                      </div>
                    </div>

                    <div className="bg-green-800 p-6 rounded-[2rem] text-white shadow-2xl shadow-green-900/20">
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="text-[10px] font-black text-green-100/50 uppercase tracking-widest mb-1">Valor para Quitação Total</p>
                          <p className="text-3xl font-black">{formatCurrency(totalQuitacao)}</p>
                        </div>
                        <div className="bg-white/10 p-4 rounded-2xl">
                          <Wallet size={24} className="text-green-100" />
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      )}

      {/* Modal Adicionar */}
      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-lg p-8 rounded-t-[2.5rem] sm:rounded-[3rem] shadow-2xl animate-in slide-in-from-bottom sm:zoom-in duration-300">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-2xl font-black text-gray-900">Novo Parcelamento</h2>
              <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-900 transition"><LucideX size={24} /></button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 ml-1 tracking-[0.1em]">Descrição</label>
                <input 
                  type="text" 
                  value={formData.desc} 
                  onChange={e => setFormData({...formData, desc: e.target.value})}
                  className="w-full bg-gray-50 border border-gray-200 rounded-2xl px-6 py-5 outline-none focus:border-green-700 font-bold text-lg"
                  placeholder="Ex: IPhone 15 Pro, Notebook..."
                  required
                />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="sm:col-span-1">
                  <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 ml-1 tracking-[0.1em]">Valor Parcela</label>
                  <input 
                    type="text" 
                    inputMode="numeric"
                    value={formData.val} 
                    onChange={e => setFormData({...formData, val: maskCurrency(e.target.value)})}
                    className="w-full bg-gray-50 border border-gray-200 rounded-2xl px-6 py-5 outline-none focus:border-green-700 font-black text-xl"
                    required
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 ml-1 tracking-[0.1em]">Parc. Atual</label>
                  <input 
                    type="number" 
                    value={formData.atual} 
                    onChange={e => setFormData({...formData, atual: e.target.value})}
                    className="w-full bg-gray-50 border border-gray-200 rounded-2xl px-6 py-5 outline-none focus:border-green-700 font-black text-xl text-center"
                    required
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 ml-1 tracking-[0.1em]">Parc. Restante</label>
                  <input 
                    type="number" 
                    value={formData.restante} 
                    onChange={e => setFormData({...formData, restante: e.target.value})}
                    className="w-full bg-gray-50 border border-gray-200 rounded-2xl px-6 py-5 outline-none focus:border-green-700 font-black text-xl text-center"
                    required
                  />
                </div>
              </div>

              <div className="bg-blue-50 p-5 rounded-2xl border border-blue-100 flex items-start gap-3">
                <Info size={20} className="text-blue-600 shrink-0 mt-0.5" />
                <p className="text-[10px] font-bold text-blue-800 leading-normal uppercase">
                  O valor de quitação será calculado somando a parcela atual com todas as restantes.
                </p>
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  type="button" 
                  onClick={() => setShowModal(false)}
                  className="flex-1 bg-gray-100 text-gray-500 font-black py-5 rounded-2xl uppercase tracking-widest text-xs"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 bg-green-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-green-900/20 uppercase tracking-widest text-xs"
                >
                  Confirmar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Installments;

