  mes_id: number;
  banco_id: number;
  descricao: string;
  valor: number;
  pago: boolean;
  data: string;
}

export interface Installment {
  id: number;
  mes_id: number;
  descricao: string;
  valor_parcela: number;
  parcela_atual: number;
  total_parcelas: number;
  criado_em?: string;
}

import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp, CalendarPlus } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Installment, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    const { data: allMonths, error } = await supabaseClient
      .from('meses')
      .select('*')
      .order('criado_em', { ascending: false });

    if (error || !allMonths) {
      setMonths([]);
      setLoading(false);
      return;
    }

    let finalMonths = [...allMonths];
    const activeMonth = finalMonths.find(m => m.status === 'ativo');

    if (activeMonth) {
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
      let idx = meses_nomes.indexOf(activeMonth.nome.toUpperCase());
      let nextIdx = idx + 1;
      let nextYear = activeMonth.ano;

      if (nextIdx > 11) {
        nextIdx = 0;
        nextYear++;
      }
      const nextMonthName = meses_nomes[nextIdx];

      const nextMonthExists = finalMonths.some(m => m.nome === nextMonthName && m.ano === nextYear);

      if (!nextMonthExists) {
        const { data: newProvisionMonth, error: insertError } = await supabaseClient
          .from('meses')
          .insert([{ nome: nextMonthName, ano: nextYear, status: 'provisionamento' }])
          .select()
          .single();

        if (newProvisionMonth && !insertError) {
          finalMonths.push(newProvisionMonth);
        }
      }
    }

    const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

    finalMonths.sort((a, b) => {
      const statusA = statusOrder[a.status] || 99;
      const statusB = statusOrder[b.status] || 99;

      if (statusA !== statusB) {
        return statusA - statusB;
      }

      if (a.status === 'fechado') {
        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      }
      return new Date(b.criado_em!).getTime() - new Date(a.criado_em!).getTime();
    });

    setMonths(finalMonths);
    setLoading(false);
  };

  const closeMonthRoutine = async () => {
    if (!confirm(`Isso fechará o mês de ${currentMonth.nome} e criará o próximo. Os parcelamentos ativos serão transferidos com a parcela incrementada (+1). Deseja continuar?`)) return;

    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor', { count: 'exact' }).eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = idx + 1;
    let nextYear = currentMonth.ano;

    if (nextIdx > 11) { 
      nextIdx = 0; 
      nextYear++;
    }
    const nextMonthName = meses_nomes[nextIdx];

    const { data: existingNextMonth } = await supabaseClient
      .from('meses')
      .select('id, status')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear)
      .limit(1)
      .single();

    let nextMonth;

    if (existingNextMonth) {
      const { data, error } = await supabaseClient
        .from('meses')
        .update({ status: 'ativo' })
        .eq('id', existingNextMonth.id)
        .select()
        .single();
      if (error) {
        alert("Erro ao ativar o mês provisionado: " + error.message);
        return;
      }
      nextMonth = data;
    } else {
      const { data, error } = await supabaseClient
        .from('meses')
        .insert([{ nome: nextMonthName, ano: nextYear, status: 'ativo' }])
        .select()
        .single();
      if (error) {
        alert("Erro ao criar o próximo mês: " + error.message);
        return;
      }
      nextMonth = data;
    }

    if (!nextMonth) {
      alert("Falha crítica ao ativar ou criar o próximo mês.");
      return;
    }

    const { data: currentInstallments } = await supabaseClient
      .from('parcelamentos')
      .select('*')
      .eq('mes_id', currentMonth.id);

    if (currentInstallments && currentInstallments.length > 0) {
      const pendingInstallments = currentInstallments.filter((inst: Installment) => inst.parcela_atual < inst.total_parcelas);

      if (pendingInstallments.length > 0) {
        const nextInstallments = pendingInstallments.map((inst: Installment) => ({
          mes_id: nextMonth.id,
          descricao: inst.descricao,
          valor_parcela: inst.valor_parcela,
          parcela_atual: inst.parcela_atual + 1,
          total_parcelas: inst.total_parcelas
        }));
        await supabaseClient.from('parcelamentos').insert(nextInstallments);
      }
    }

    alert(`Ciclo encerrado! Novo mês ativado: ${nextMonth.nome}/${nextMonth.ano}.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8">
      {currentMonth.status === 'ativo' && (
        <div className="bg-red-50 border border-red-100 p-8 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="bg-red-100 p-4 rounded-full text-red-700">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-xl font-bold text-red-900">Encerrar Ciclo Mensal</h3>
              <p className="text-red-700/60 max-w-sm">Ao fechar o mês, o sistema calcula o saldo final, bloqueia edições e ativa o próximo mês automaticamente.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="bg-red-600 text-white px-8 py-3 rounded-full font-bold hover:bg-red-700 transition shadow-lg shadow-red-600/20 active:scale-95"
          >
            Fechar Mês de {currentMonth.nome}
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
        <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
          <Calendar className="text-gray-400" />
          Histórico de Meses
        </h3>

        {loading ? <p className="text-center py-10">Carregando histórico...</p> : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div key={m.id} className="p-6 rounded-2xl border border-gray-100 bg-gray-50/30 flex items-center justify-between group hover:border-green-200 transition">
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl ${
                      m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                      m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                      'bg-gray-100 text-gray-500'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={20} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={20} /> :
                     <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-800 uppercase tracking-tight">{m.nome} / {m.ano}</h4>
                    <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-0.5 rounded-md ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-lg font-bold text-gray-900">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-xs text-gray-400 font-medium">{m.status === 'ativo' ? 'Em andamento' : 'Provisionado'}</p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-1 text-xs font-bold text-green-700 hover:underline flex items-center gap-1 ml-auto"
                  >
                    Visualizar <TrendingUp size={12} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { Banknote, Plus, ChevronRight, ArrowLeft, Trash2, CheckCircle2, Circle, Save, Info, X as LucideX } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Bank, BankExpense } from '../types';

interface BanksProps {
  currentMonth: Month;
  // FIX: Add triggerAdd prop to handle global add button clicks, resolving the type error in App.tsx.
  triggerAdd: number;
}

const Banks: React.FC<BanksProps> = ({ currentMonth, triggerAdd }) => {
  const [banks, setBanks] = useState<Bank[]>([]);
  const [selectedBank, setSelectedBank] = useState<Bank | null>(null);
  const [bankExpenses, setBankExpenses] = useState<BankExpense[]>([]);
  const [loading, setLoading] = useState(true);

  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);
  const [specialFields, setSpecialFields] = useState<{ [key: string]: string }>({});
  const [saving, setSaving] = useState(false);

  const [showBankModal, setShowBankModal] = useState(false);
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [bankForm, setBankForm] = useState({ nome: '', cor: '#15803d' });
  const [expForm, setExpForm] = useState({ desc: '', val: 'R$ 0,00', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchBanks();
  }, []);

  // FIX: Handle triggerAdd prop to open the "add bank" modal when the global add button is clicked.
  useEffect(() => {
    if (triggerAdd > 0 && !selectedBank) {
      setBankForm({ nome: '', cor: '#15803d' });
      setShowBankModal(true);
    }
  }, [triggerAdd]);

  useEffect(() => {
    if (selectedBank) {
      fetchBankExpenses();
    }
  }, [selectedBank, currentMonth]);

  const fetchBanks = async () => {
    try {
      const { data, error } = await supabaseClient.from('bancos').select('*').order('nome');
      if (error) throw error;
      setBanks(data || []);
    } catch (err) {
      console.error("Erro ao buscar bancos:", err);
    } finally {
      setLoading(false);
    }
  };

  const maskCurrency = (value: string) => {
    const digits = value.replace(/\D/g, "");
    const amount = Number(digits) / 100;
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(amount);
  };

  const parseCurrency = (value: string) => {
    return parseFloat(value.replace(/[^\d,]/g, '').replace(',', '.')) || 0;
  };

  const fetchBankExpenses = async () => {
    if (!selectedBank) return;
    const { data } = await supabaseClient
      .from('banco_despesas')
      .select('*')
      .eq('banco_id', selectedBank.id)
      .eq('mes_id', currentMonth.id)
      .order('data', { ascending: true });

    setBankExpenses(data || []);

    const isSpecial = selectedBank.nome === 'American Express' || selectedBank.nome === 'BB';
    if (isSpecial) {
      const initialFields: { [key: string]: string } = {};
      const fields = selectedBank.nome === 'American Express' 
        ? ['Compras à Vista', 'Em Processamento'] 
        : ['Compras à Vista', 'Em Processamento', 'Parceladas'];

      fields.forEach(f => {
        const found = data?.find(d => d.descricao === f);
        initialFields[f] = maskCurrency(found ? (found.valor * 100).toString() : '0');
      });
      setSpecialFields(initialFields);
    }
  };

  const handleCreateBank = async (e: React.FormEvent) => {
    e.preventDefault();
    const { error } = await supabaseClient.from('bancos').insert([bankForm]);
    if (error) {
      alert("Erro ao criar: " + error.message);
    } else {
      setShowBankModal(false);
      setBankForm({ nome: '', cor: '#15803d' });
      fetchBanks();
    }
  };

  const handleDeleteBank = async (id: number, name: string) => {
    if (currentMonth.status === 'fechado') return;
    try {
      const { error } = await supabaseClient.from('bancos').delete().eq('id', id);
      if (error) {
        if (error.code === '23503') {
          alert(`Não foi possível excluir o banco "${name}". Remova os gastos primeiro.`);
        } else {
          alert("Erro: " + error.message);
        }
      } else {
        setBanks(prev => prev.filter(b => b.id !== id));
        setConfirmDeleteId(null);
      }
    } catch (err: any) {
      alert("Erro fatal: " + err.message);
    }
  };

  const handleCreateExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBank) return;
    const val = parseCurrency(expForm.val);
    if (val <= 0) return;

    await supabaseClient.from('banco_despesas').insert([{
      mes_id: currentMonth.id,
      banco_id: selectedBank.id,
      descricao: expForm.desc,
      valor: val,
      pago: true,
      data: expForm.date
    }]);

    setShowExpenseModal(false);
    setExpForm({ desc: '', val: 'R$ 0,00', date: new Date().toISOString().split('T')[0] });
    fetchBankExpenses();
  };

  const handleDeleteExpense = async (id: number) => {
    if (currentMonth.status === 'fechado') return;
    await supabaseClient.from('banco_despesas').delete().eq('id', id);
    fetchBankExpenses();
  };

  const handleSaveSpecial = async () => {
    if (!selectedBank) return;
    setSaving(true);
    try {
      const fields = Object.keys(specialFields);
      for (const field of fields) {
        const val = parseCurrency(specialFields[field]);
        const existing = bankExpenses.find(e => e.descricao === field);
        if (existing) {
          await supabaseClient.from('banco_despesas').update({ valor: val }).eq('id', existing.id);
        } else {
          await supabaseClient.from('banco_despesas').insert([{
            mes_id: currentMonth.id,
            banco_id: selectedBank.id,
            descricao: field,
            valor: val,
            pago: true,
            data: new Date().toISOString().split('T')[0]
          }]);
        }
      }
      alert("Dados de " + selectedBank.nome + " salvos!");
      fetchBankExpenses();
    } catch (error) {
      alert("Erro ao salvar.");
    } finally {
      setSaving(false);
    }
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (selectedBank) {
    const total = bankExpenses.reduce((acc, curr) => acc + curr.valor, 0);
    const isSpecial = selectedBank.nome === 'American Express' || selectedBank.nome === 'BB';

    return (
      <div className="space-y-6 animate-in slide-in-from-right duration-300">
        <button onClick={() => setSelectedBank(null)} className="flex items-center gap-2 text-gray-500 hover:text-gray-900 transition font-bold">
          <ArrowLeft size={18} /> Voltar
        </button>

        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-6 lg:p-10">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-10">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-xl shadow-gray-200" style={{ backgroundColor: selectedBank.cor, color: selectedBank.nome === 'BB' ? '#003366' : 'white' }}>
                <Banknote size={32} />
              </div>
              <div>
                <h3 className="text-2xl font-black text-gray-900">{selectedBank.nome}</h3>
                <p className="text-sm text-gray-500 font-bold uppercase tracking-widest">{formatCurrency(total)}</p>
              </div>
            </div>
            {!isSpecial && currentMonth.status === 'ativo' && (
              <button onClick={() => setShowExpenseModal(true)} className="w-full sm:w-auto bg-green-800 text-white px-6 py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-2 shadow-lg">
                <Plus size={20} /> Novo Lançamento
              </button>
            )}
          </div>

          {isSpecial ? (
            <div className="max-w-xl mx-auto space-y-6 bg-gray-50 p-6 lg:p-10 rounded-[2.5rem] border border-gray-100">
              <div className="flex items-center gap-3 text-blue-800 mb-6 bg-blue-50 p-4 rounded-2xl border border-blue-100">
                <Info size={24} className="shrink-0" />
                <span className="text-xs font-bold leading-tight uppercase tracking-wider">Gestão global de saldo para {selectedBank.nome}</span>
              </div>

              <div className="space-y-6">
                {Object.keys(specialFields).map(f => (
                  <div key={f}>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">{f}</label>
                    <input 
                      type="text" 
                      inputMode="numeric"
                      value={specialFields[f]} 
                      onChange={e => setSpecialFields({...specialFields, [f]: maskCurrency(e.target.value)})}
                      className="w-full bg-white border border-gray-200 rounded-2xl px-5 py-5 outline-none focus:border-green-700 font-black text-2xl text-gray-800 transition"
                      disabled={currentMonth.status === 'fechado'}
                    />
                  </div>
                ))}
              </div>

              {currentMonth.status === 'ativo' && (
                <button onClick={handleSaveSpecial} disabled={saving} className="w-full bg-green-800 text-white font-black py-6 rounded-2xl shadow-2xl hover:bg-green-900 transition flex items-center justify-center gap-3 mt-10">
                  {saving ? <div className="h-6 w-6 animate-spin rounded-full border-3 border-white border-t-transparent" /> : <Save size={24} />}
                  Salvar {selectedBank.nome}
                </button>
              )}
            </div>
          ) : (
            <div className="space-y-3">
              {bankExpenses.length === 0 ? (
                <div className="py-20 text-center">
                  <div className="bg-gray-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Banknote className="text-gray-200" size={40} />
                  </div>
                  <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Sem lançamentos</p>
                </div>
              ) : (
                bankExpenses.map(exp => (
                  <div key={exp.id} className="flex items-center justify-between p-5 rounded-2xl border border-gray-100 bg-white hover:border-green-200 transition">
                    <div className="flex items-center gap-4">
                      <div className="bg-green-50 p-3 rounded-xl text-green-700"><CheckCircle2 size={20} /></div>
                      <div>
                        <h4 className="font-black text-gray-800">{exp.descricao}</h4>
                        <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-6">
                      <span className="font-black text-lg text-gray-900">{formatCurrency(exp.valor)}</span>
                      {currentMonth.status === 'ativo' && (
                        <button onClick={() => handleDeleteExpense(exp.id)} className="text-gray-300 hover:text-red-500 transition-colors p-2">
                          <Trash2 size={20} />
                        </button>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </div>

        {showExpenseModal && (
