import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp, CalendarPlus } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Installment, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    let { data: allMonths, error } = await supabaseClient
      .from('meses')
      .select('*')
      .order('criado_em', { ascending: false });

    if (error || !allMonths) {
      setMonths([]);
      setLoading(false);
      return;
    }

    const activeMonth = allMonths.find(m => m.status === 'ativo');

    if (activeMonth) {
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
      let idx = meses_nomes.indexOf(activeMonth.nome.toUpperCase());
      let nextIdx = idx + 1;
      let nextYear = activeMonth.ano;

      if (nextIdx > 11) {
        nextIdx = 0;
        nextYear++;
      }
      const nextMonthName = meses_nomes[nextIdx];

      const nextMonthExists = allMonths.some(m => m.nome === nextMonthName && m.ano === nextYear);

      if (!nextMonthExists) {
        const { error: insertError } = await supabaseClient
          .from('meses')
          .insert([{ nome: nextMonthName, ano: nextYear, status: 'provisionamento' }]);

        // Se a inserção foi bem-sucedida, busca novamente para garantir a consistência dos dados
        if (!insertError) {
          const { data: updatedMonths } = await supabaseClient
            .from('meses')
            .select('*')
            .order('criado_em', { ascending: false });
          allMonths = updatedMonths || [];
        }
      }
    }

    const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

    allMonths.sort((a, b) => {
      const statusA = statusOrder[a.status] || 99;
      const statusB = statusOrder[b.status] || 99;

      if (statusA !== statusB) {
        return statusA - statusB;
      }

      if (a.status === 'fechado') {
        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      }
      return new Date(b.criado_em!).getTime() - new Date(a.criado_em!).getTime();
    });

    setMonths(allMonths);
    setLoading(false);
  };

  const closeMonthRoutine = async () => {
    if (!confirm(`Isso fechará o mês de ${currentMonth.nome} e criará o próximo. Os parcelamentos ativos serão transferidos com a parcela incrementada (+1). Deseja continuar?`)) return;

    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor', { count: 'exact' }).eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = idx + 1;
    let nextYear = currentMonth.ano;

    if (nextIdx > 11) { 
      nextIdx = 0; 
      nextYear++;
    }
    const nextMonthName = meses_nomes[nextIdx];

    const { data: existingNextMonth } = await supabaseClient
      .from('meses')
      .select('id, status')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear)
      .limit(1)
      .single();

    let nextMonth;

    if (existingNextMonth) {
      const { data, error } = await supabaseClient
        .from('meses')
        .update({ status: 'ativo' })
        .eq('id', existingNextMonth.id)
        .select()
        .single();
      if (error) {
        alert("Erro ao ativar o mês provisionado: " + error.message);
        return;
      }
      nextMonth = data;
    } else {
      const { data, error } = await supabaseClient
        .from('meses')
        .insert([{ nome: nextMonthName, ano: nextYear, status: 'ativo' }])
        .select()
        .single();
      if (error) {
        alert("Erro ao criar o próximo mês: " + error.message);
        return;
      }
      nextMonth = data;
    }

    if (!nextMonth) {
      alert("Falha crítica ao ativar ou criar o próximo mês.");
      return;
    }

    const { data: currentInstallments } = await supabaseClient
      .from('parcelamentos')
      .select('*')
      .eq('mes_id', currentMonth.id);

    if (currentInstallments && currentInstallments.length > 0) {
      const pendingInstallments = currentInstallments.filter((inst: Installment) => inst.parcela_atual < inst.total_parcelas);

      if (pendingInstallments.length > 0) {
        const nextInstallments = pendingInstallments.map((inst: Installment) => ({
          mes_id: nextMonth.id,
          descricao: inst.descricao,
          valor_parcela: inst.valor_parcela,
          parcela_atual: inst.parcela_atual + 1,
          total_parcelas: inst.total_parcelas
        }));
        await supabaseClient.from('parcelamentos').insert(nextInstallments);
      }
    }

    alert(`Ciclo encerrado! Novo mês ativado: ${nextMonth.nome}/${nextMonth.ano}.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8">
      {currentMonth.status === 'ativo' && (
        <div className="bg-red-50 border border-red-100 p-8 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="bg-red-100 p-4 rounded-full text-red-700">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-xl font-bold text-red-900">Encerrar Ciclo Mensal</h3>
              <p className="text-red-700/60 max-w-sm">Ao fechar o mês, o sistema calcula o saldo final, bloqueia edições e ativa o próximo mês automaticamente.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="bg-red-600 text-white px-8 py-3 rounded-full font-bold hover:bg-red-700 transition shadow-lg shadow-red-600/20 active:scale-95"
          >
            Fechar Mês de {currentMonth.nome}
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8">
        <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
          <Calendar className="text-gray-400" />
          Histórico de Meses
        </h3>

        {loading ? <p className="text-center py-10">Carregando histórico...</p> : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div key={m.id} className="p-6 rounded-2xl border border-gray-100 bg-gray-50/30 flex items-center justify-between group hover:border-green-200 transition">
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl ${
                      m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                      m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                      'bg-gray-100 text-gray-500'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={20} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={20} /> :
                     <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-800 uppercase tracking-tight">{m.nome} / {m.ano}</h4>
                    <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-0.5 rounded-md ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-lg font-bold text-gray-900">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-xs text-gray-400 font-medium">{m.status === 'ativo' ? 'Em andamento' : 'Provisionado'}</p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-1 text-xs font-bold text-green-700 hover:underline flex items-center gap-1 ml-auto"
                  >
                    Visualizar <TrendingUp size={12} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp, CalendarPlus, ChevronRight } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Installment, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    try {
      let { data: allMonths, error } = await supabaseClient
        .from('meses')
        .select('*')
        .order('criado_em', { ascending: false });

      if (error || !allMonths) {
        setMonths([]);
        setLoading(false);
        return;
      }

      // Buscar o mês que está atualmente ATIVO para calcular o próximo
      const activeMonth = allMonths.find(m => m.status === 'ativo');

      if (activeMonth) {
        const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
        let idx = meses_nomes.indexOf(activeMonth.nome.toUpperCase());
        let nextIdx = idx + 1;
        let nextYear = activeMonth.ano;

        if (nextIdx > 11) {
          nextIdx = 0;
          nextYear++;
        }
        const nextMonthName = meses_nomes[nextIdx];

        // Verificar se esse próximo mês já existe na lista
        const nextMonthExists = allMonths.some(m => m.nome.toUpperCase() === nextMonthName && m.ano === nextYear);

        if (!nextMonthExists) {
          // Criar o mês de provisionamento se ele não existir
          const { error: insertError } = await supabaseClient
            .from('meses')
            .insert([{ nome: nextMonthName, ano: nextYear, status: 'provisionamento' }]);

          if (!insertError) {
            // Recarregar a lista para incluir o novo mês criado
            const { data: updatedMonths } = await supabaseClient
              .from('meses')
              .select('*')
              .order('criado_em', { ascending: false });
            allMonths = updatedMonths || [];
          }
        }
      }

      // Ordenação: Ativo > Provisionamento > Fechados
      const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

      const sortedMonths = [...allMonths].sort((a, b) => {
        const statusA = statusOrder[a.status] || 99;
        const statusB = statusOrder[b.status] || 99;

        if (statusA !== statusB) return statusA - statusB;

        // Dentro do mesmo status, ordenar por ano e mês descendente
        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      });

      setMonths(sortedMonths);
    } catch (err) {
      console.error("Erro ao processar meses:", err);
    } finally {
      setLoading(false);
    }
  };

  const closeMonthRoutine = async () => {
    if (!confirm(`Isso fechará o mês de ${currentMonth.nome} e ativará o próximo mês (que já pode conter lançamentos provisionados). Deseja continuar?`)) return;

    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    // 1. Fechar o atual
    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // 2. Localizar o mês de provisionamento para ativá-lo
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = idx + 1;
    let nextYear = currentMonth.ano;
    if (nextIdx > 11) { nextIdx = 0; nextYear++; }
    const nextMonthName = meses_nomes[nextIdx];

    const { data: nextMonthData } = await supabaseClient
      .from('meses')
      .select('*')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear)
      .single();

    if (nextMonthData) {
      await supabaseClient.from('meses').update({ status: 'ativo' }).eq('id', nextMonthData.id);

      // 3. Transferir parcelamentos
      const { data: currentInstallments } = await supabaseClient
        .from('parcelamentos')
        .select('*')
        .eq('mes_id', currentMonth.id);

      if (currentInstallments && currentInstallments.length > 0) {
        const pending = currentInstallments.filter((inst: Installment) => inst.parcela_atual < inst.total_parcelas);
        if (pending.length > 0) {
          const nextInstallments = pending.map((inst: Installment) => ({
            mes_id: nextMonthData.id,
            descricao: inst.descricao,
            valor_parcela: inst.valor_parcela,
            parcela_atual: inst.parcela_atual + 1,
            total_parcelas: inst.total_parcelas
          }));
          await supabaseClient.from('parcelamentos').insert(nextInstallments);
        }
      }
    }

    alert(`Mês encerrado! O próximo mês agora está ATIVO.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
