import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp, CalendarPlus, ChevronRight } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Installment, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    try {
      let { data: allMonths, error } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      if (error || !allMonths) {
        setMonths([]);
        setLoading(false);
        return;
      }

      const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

      const sortedMonths = [...allMonths].sort((a, b) => {
        const statusA = statusOrder[a.status] || 99;
        const statusB = statusOrder[b.status] || 99;

        if (statusA !== statusB) return statusA - statusB;

        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      });

      setMonths(sortedMonths);
    } catch (err) {
      console.error("Erro ao processar meses:", err);
    } finally {
      setLoading(false);
    }
  };

  const closeMonthRoutine = async () => {
    if (currentMonth.status !== 'ativo') {
      alert("Apenas o mês ativo pode ser encerrado.");
      return;
    }

    if (!confirm(`Isso fechará o mês de ${currentMonth.nome} e ativará o mês seguinte. Deseja continuar?`)) return;

    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // Ativar o mês de provisionamento
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = (idx + 1) % 12;
    let nextYear = idx === 11 ? currentMonth.ano + 1 : currentMonth.ano;
    const nextMonthName = meses_nomes[nextIdx];

    const { data: nextMonthData } = await supabaseClient
      .from('meses')
      .select('*')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear)
      .single();

    if (nextMonthData) {
      await supabaseClient.from('meses').update({ status: 'ativo' }).eq('id', nextMonthData.id);

      const { data: currentInstallments } = await supabaseClient
        .from('parcelamentos')
        .select('*')
        .eq('mes_id', currentMonth.id);

      if (currentInstallments && currentInstallments.length > 0) {
        const pending = currentInstallments.filter((inst: Installment) => inst.parcela_atual < inst.total_parcelas);
        if (pending.length > 0) {
          const nextInstallments = pending.map((inst: Installment) => ({
            mes_id: nextMonthData.id,
            descricao: inst.descricao,
            valor_parcela: inst.valor_parcela,
            parcela_atual: inst.parcela_atual + 1,
            total_parcelas: inst.total_parcelas
          }));
          await supabaseClient.from('parcelamentos').insert(nextInstallments);
        }
      }
    }

    alert(`Mês encerrado com sucesso!`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      {currentMonth.status === 'ativo' && (
        <div className="bg-red-50 border border-red-100 p-6 sm:p-8 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-6 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-red-100 p-3 sm:p-4 rounded-full text-red-700">
              <LockKeyhole size={24} className="sm:w-8 sm:h-8" />
            </div>
            <div>
              <h3 className="text-lg sm:text-xl font-black text-red-900 uppercase tracking-tight">Fechar Mês Atual</h3>
              <p className="text-red-700/60 text-xs sm:text-sm font-medium">Finaliza o ciclo de {currentMonth.nome} e ativa o planejamento.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="w-full md:w-auto bg-red-600 text-white px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-red-700 transition shadow-lg shadow-red-600/20"
          >
            Encerrar Ciclo
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-6 sm:p-8">
        <h3 className="text-lg font-black mb-6 flex items-center gap-2 text-gray-800">
          <Calendar className="text-gray-400" size={20} />
          LINHA DO TEMPO
        </h3>

        {loading ? (
          <div className="py-20 flex flex-col items-center gap-3">
            <div className="w-8 h-8 border-3 border-green-700 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase text-gray-400">Carregando Histórico...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-3 sm:gap-4">
            {months.map(m => (
              <div 
                key={m.id} 
                className={`p-5 rounded-[1.5rem] border flex items-center justify-between transition group ${
                  m.status === 'ativo' ? 'bg-green-50/30 border-green-100 hover:border-green-300' :
                  m.status === 'provisionamento' ? 'bg-blue-50/30 border-blue-200 hover:border-blue-400 shadow-blue-100 shadow-md' :
                  'bg-gray-50/30 border-gray-100 hover:border-gray-200'
                }`}
              >
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl shadow-sm ${
                      m.status === 'ativo' ? 'bg-green-600 text-white' :
                      m.status === 'provisionamento' ? 'bg-blue-600 text-white' :
                      'bg-white text-gray-400 border border-gray-100'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={18} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={18} /> :
                     <LockKeyhole size={18} />}
                  </div>
                  <div>
                    <h4 className="font-black text-gray-800 text-sm sm:text-base tracking-tight uppercase">{m.nome} {m.ano}</h4>
                    <span className={`text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700 font-black' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status === 'provisionamento' ? 'PLANEJAMENTO' : m.status}
                    </span>
                  </div>
                </div>

                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-sm sm:text-base font-black text-gray-900 tracking-tight">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
                      {m.status === 'ativo' ? 'Mês Atual' : 'Lançar Futuro'}
                    </p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className={`mt-1 text-[10px] font-black uppercase tracking-widest flex items-center gap-1 ml-auto transition-colors ${
                      m.status === 'provisionamento' ? 'text-blue-700' : 'text-green-700'
                    }`}
                  >
                    ACESSAR <ChevronRight size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { Receipt, Zap, Trash2, CheckCircle2, Circle, Pencil, X as LucideX } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Expense, PixExpense } from '../types';

interface ExpensesProps {
  currentMonth: Month;
  triggerAdd: number;
}

const Expenses: React.FC<ExpensesProps> = ({ currentMonth, triggerAdd }) => {
  const [activeTab, setActiveTab] = useState<'contas' | 'pix'>('contas');
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [pixExpenses, setPixExpenses] = useState<PixExpense[]>([]);
  const [pixTax, setPixTax] = useState(5.0);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [formData, setFormData] = useState({ desc: '', val: 'R$ 0,00', date: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    fetchPixConfig();
    fetchData();
  }, [currentMonth, activeTab]);

  useEffect(() => {
    if (triggerAdd > 0) {
      setEditingId(null);
      setFormData({ desc: '', val: 'R$ 0,00', date: new Date().toISOString().split('T')[0] });
      setShowModal(true);
    }
  }, [triggerAdd]);

  const fetchPixConfig = async () => {
    const { data } = await supabaseClient.from('configuracoes').select('*').eq('chave', 'taxa_pix').single();
    if (data) setPixTax(parseFloat(data.valor));
  };

  const fetchData = async () => {
    setLoading(true);
    if (activeTab === 'contas') {
      const { data } = await supabaseClient
        .from('despesas_contas')
        .select('*')
        .eq('mes_id', currentMonth.id)
        .order('data', { ascending: true });
      setExpenses(data || []);
    } else {
      const { data } = await supabaseClient
        .from('despesas_pix_credito')
        .select('*')
        .eq('mes_id', currentMonth.id)
        .order('data', { ascending: true });
      setPixExpenses(data || []);
    }
    setLoading(false);
  };

  const maskCurrency = (value: string) => {
    const digits = value.replace(/\D/g, "");
    const amount = Number(digits) / 100;
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(amount);
  };

  const parseCurrency = (value: string) => {
    return parseFloat(value.replace(/[^\d,]/g, '').replace(',', '.')) || 0;
  };

  const handleTogglePaid = async (table: string, id: number, currentStatus: boolean) => {
    if (currentMonth.status === 'fechado') return;
    await supabaseClient.from(table).update({ pago: !currentStatus }).eq('id', id);
    fetchData();
  };

  const handleDelete = async (table: string, id: number) => {
    if (currentMonth.status === 'fechado' || !confirm("Deseja realmente excluir?")) return;
    await supabaseClient.from(table).delete().eq('id', id);
    fetchData();
  };

  const openEditModal = (item: any) => {
    setEditingId(item.id);
    const numericVal = item.valor || item.valor_original || 0;
    setFormData({
      desc: item.descricao,
      val: maskCurrency((numericVal * 100).toString()),
      date: item.data
    });
    setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseCurrency(formData.val);
    if (!formData.desc || val <= 0) return;

    const payload: any = {
      mes_id: currentMonth.id,
      descricao: formData.desc,
      data: formData.date
    };

    if (activeTab === 'contas') {
      payload.valor = val;
      if (editingId) {
        await supabaseClient.from('despesas_contas').update(payload).eq('id', editingId);
      } else {
        await supabaseClient.from('despesas_contas').insert([payload]);
      }
    } else {
      const finalVal = val + (val * (pixTax / 100));
      payload.valor_original = val;
      payload.taxa_percentual = pixTax;
      payload.valor_final = finalVal;
      if (editingId) {
        await supabaseClient.from('despesas_pix_credito').update(payload).eq('id', editingId);
      } else {
        await supabaseClient.from('despesas_pix_credito').insert([payload]);
      }
    }

    setShowModal(false);
    setEditingId(null);
    setFormData({ desc: '', val: 'R$ 0,00', date: new Date().toISOString().split('T')[0] });
    fetchData();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const canEdit = currentMonth.status !== 'fechado';

  return (
    <div className="space-y-4 animate-in fade-in duration-300">
      <div className="flex w-full bg-gray-200/50 p-0.5 rounded-xl gap-0.5 max-w-[200px] mx-auto border border-gray-200">
        <button 
          onClick={() => setActiveTab('contas')} 
          className={`flex-1 py-1.5 rounded-lg text-[9px] font-bold transition-all uppercase tracking-widest ${activeTab === 'contas' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-400'}`}
        >
          Fixas
        </button>
        <button 
          onClick={() => setActiveTab('pix')} 
          className={`flex-1 py-1.5 rounded-lg text-[9px] font-bold transition-all uppercase tracking-widest ${activeTab === 'pix' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-400'}`}
        >
          Pix
        </button>
      </div>

      {loading ? (
        <div className="py-20 flex flex-col items-center gap-3 text-gray-400">
          <div className="w-8 h-8 border-3 border-green-700 border-t-transparent rounded-full animate-spin"></div>
          <p className="font-bold uppercase tracking-widest text-[9px]">Sincronizando...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
          {activeTab === 'contas' ? (
            expenses.length === 0 ? <p className="col-span-full text-center py-20 text-gray-400 font-bold uppercase tracking-widest text-[10px]">Sem despesas fixas.</p> :
            expenses.map(exp => (
              <div key={exp.id} className={`bg-white p-4 rounded-2xl border transition-all shadow-sm ${exp.pago ? 'opacity-50 border-transparent bg-gray-50' : 'border-gray-100 hover:border-red-100'}`}>
                <div className="flex items-start gap-2.5 mb-3">
                  <button 
                    onClick={() => handleTogglePaid('despesas_contas', exp.id, exp.pago)} 
                    className={`shrink-0 mt-0.5 ${exp.pago ? 'text-green-600' : 'text-gray-200 hover:text-green-400'}`}
                    disabled={!canEdit}
                  >
                    {exp.pago ? <CheckCircle2 size={18} /> : <Circle size={18} />}
                  </button>
                  <div className="min-w-0">
                    <h4 className={`font-bold text-gray-800 text-sm truncate leading-tight ${exp.pago ? 'line-through' : ''}`}>{exp.descricao}</h4>
                    <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest mt-0.5">{new Date(exp.data).toLocaleDateString('pt-BR')}</p>
                  </div>
                </div>

                <div className="h-px bg-gray-50 mb-3" />

                <div className="flex items-center justify-between">
                  <span className="font-black text-base text-gray-900 tracking-tight">{formatCurrency(exp.valor)}</span>
                  <div className="flex items-center gap-0.5">
                    {canEdit && (
                      <>
                        <button onClick={() => openEditModal(exp)} className="text-gray-300 hover:text-blue-600 p-1.5"><Pencil size={16} /></button>
                        <button onClick={() => handleDelete('despesas_contas', exp.id)} className="text-gray-300 hover:text-red-500 p-1.5"><Trash2 size={16} /></button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            ))
          ) : (
            pixExpenses.length === 0 ? <p className="col-span-full text-center py-20 text-gray-400 font-bold uppercase tracking-widest text-[10px]">Sem despesas via Pix.</p> :
            pixExpenses.map(exp => (
              <div key={exp.id} className={`bg-white p-4 rounded-2xl border transition-all shadow-sm ${exp.pago ? 'opacity-50 border-transparent bg-gray-50' : 'border-gray-100 hover:border-yellow-100'}`}>
                <div className="flex items-start gap-2.5 mb-3">
                  <button 
                    onClick={() => handleTogglePaid('despesas_pix_credito', exp.id, exp.pago)} 
                    className={`shrink-0 mt-0.5 ${exp.pago ? 'text-green-600' : 'text-gray-200 hover:text-green-400'}`}
                    disabled={!canEdit}
                  >
                    {exp.pago ? <CheckCircle2 size={18} /> : <Circle size={18} />}
                  </button>
                  <div className="min-w-0">
                    <h4 className={`font-bold text-gray-800 text-sm truncate leading-tight ${exp.pago ? 'line-through' : ''}`}>{exp.descricao}</h4>
                    <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest mt-0.5">Taxa: {exp.taxa_percentual}%</p>
                  </div>
                </div>

                <div className="h-px bg-gray-50 mb-3" />

                <div className="flex items-center justify-between">
                  <span className="font-black text-base text-gray-900 tracking-tight">{formatCurrency(exp.valor_final)}</span>
                  <div className="flex items-center gap-0.5">
                    {canEdit && (
                      <>
                        <button onClick={() => openEditModal(exp)} className="text-gray-300 hover:text-blue-600 p-1.5"><Pencil size={16} /></button>
                        <button onClick={() => handleDelete('despesas_pix_credito', exp.id)} className="text-gray-300 hover:text-red-500 p-1.5"><Trash2 size={16} /></button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm p-6 rounded-3xl shadow-2xl animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-black text-gray-900 uppercase tracking-tight">{editingId ? 'Editar' : 'Novo Gasto'}</h2>
              <button onClick={() => setShowModal(false)} className="text-gray-400"><LucideX size={20} /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-[9px] font-bold text-gray-400 uppercase mb-1.5 tracking-widest">Descrição</label>
                <input type="text" value={formData.desc} onChange={e => setFormData({...formData, desc: e.target.value})} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2.5 outline-none focus:border-green-700 font-bold text-sm" placeholder="Mercado, Net..." required />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div className="min-w-0">
                  <label className="block text-[9px] font-bold text-gray-400 uppercase mb-1.5 tracking-widest">Valor</label>
                  <input type="text" inputMode="numeric" value={formData.val} onChange={e => setFormData({...formData, val: maskCurrency(e.target.value)})} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2.5 outline-none focus:border-green-700 font-black text-sm" required />
                </div>
                <div className="min-w-0">
                  <label className="block text-[9px] font-bold text-gray-400 uppercase mb-1.5 tracking-widest">Data</label>
                  <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2.5 outline-none focus:border-green-700 font-bold text-xs" required />
                </div>
              </div>
              <div className="flex gap-3 pt-3">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 bg-gray-100 text-gray-500 font-bold py-3.5 rounded-xl uppercase text-[10px] tracking-widest">Sair</button>
                <button type="submit" className="flex-1 bg-green-800 text-white font-bold py-3.5 rounded-xl shadow-md uppercase text-[10px] tracking-widest">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

