                  <span className="text-sm font-black text-gray-800 uppercase leading-none mt-1">{provisionMonth.nome} {provisionMonth.ano}</span>
                  {currentContextMonth.id === provisionMonth.id && <div className="absolute -bottom-1 w-1 h-1 bg-blue-600 rounded-full" />}
                </button>
              )}

              {currentContextMonth.status === 'fechado' && (
