                  </div>
                </>
              )}
            </div>

            {/* Ações Rápidas */}
            <div className="flex items-center gap-2 self-center lg:self-auto">
              {showAddAction && canEdit && (
                <button 
                  onClick={onAddClick}
                  className="bg-gray-900 text-white p-3 rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all"
