import { supabaseClient } from '../services/supabase';
import { Month, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    try {
      let { data: allMonths, error } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      if (error || !allMonths) {
        setMonths([]);
        setLoading(false);
        return;
      }

      // Ordenação: Ativo Primeiro, Provisionamento Segundo, Fechados Depois (Cronológico)
      const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

      const sortedMonths = [...allMonths].sort((a, b) => {
        const statusA = statusOrder[a.status] || 99;
        const statusB = statusOrder[b.status] || 99;

        if (statusA !== statusB) return statusA - statusB;

        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      });

      setMonths(sortedMonths);
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    } finally {
      setLoading(false);
    }
  };

  const closeMonthRoutine = async () => {
    if (currentMonth.status !== 'ativo') {
      alert("Apenas o mês ativo pode ser encerrado.");
      return;
    }

    if (!confirm(`Deseja encerrar ${currentMonth.nome}/${currentMonth.ano}? Esta ação é irreversível e bloqueará edições.`)) return;

    // Cálculo do Saldo Final para Registro Histórico
    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    // 1. Fecha o mês atual
    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // 2. Busca e Ativa o mês de planejamento (Jan/2026 se for Dez/2025)
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = (idx + 1) % 12;
    let nextYear = idx === 11 ? currentMonth.ano + 1 : currentMonth.ano;
    const nextMonthName = meses_nomes[nextIdx];

    const { data: nextMonthData } = await supabaseClient
      .from('meses')
      .select('*')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear)
      .single();

    if (nextMonthData) {
      // Ativa o próximo mês. 
      // REGRA WHITE LABEL: Não clonamos nada. O próximo mês deve estar vazio/zerado.
      await supabaseClient.from('meses').update({ status: 'ativo' }).eq('id', nextMonthData.id);
    }

    alert(`Mês de ${currentMonth.nome} encerrado. O novo ciclo começou.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20">
      {/* Ação de Fechamento (Apenas no contexto ativo) */}
      {currentMonth.status === 'ativo' && (
        <div className="bg-gray-900 p-8 sm:p-12 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-2xl">
          <div className="flex items-center gap-6 text-white">
            <div className="bg-white/10 p-5 rounded-3xl backdrop-blur-sm border border-white/5">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black uppercase tracking-tighter leading-none mb-2">Encerrar Ciclo</h3>
              <p className="text-white/40 text-xs font-bold uppercase tracking-widest max-w-xs">Finaliza {currentMonth.nome} e ativa o planejamento como novo ciclo real.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="w-full md:w-auto bg-white text-gray-900 px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-gray-100 transition shadow-xl active:scale-95"
          >
            Fechar Mês Agora
          </button>
        </div>
      )}

      {/* Grid de Histórico */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 lg:p-12">
        <h3 className="text-xl font-black mb-10 flex items-center gap-3 text-gray-800">
          <Calendar className="text-gray-400" size={24} />
          ARQUIVO MENSAL
        </h3>

        {loading ? (
          <div className="py-24 flex flex-col items-center gap-4">
            <div className="w-10 h-10 border-4 border-gray-900 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Varrendo Registros...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div 
                key={m.id} 
                className={`p-6 rounded-[1.8rem] border flex items-center justify-between transition-all group ${
                  m.status === 'ativo' ? 'bg-green-50/20 border-green-100' :
                  m.status === 'provisionamento' ? 'bg-blue-50/20 border-blue-100' :
                  'bg-gray-50/30 border-gray-100 hover:border-gray-200'
                }`}
              >
                <div className="flex items-center gap-5">
                  <div className={`p-4 rounded-2xl shadow-sm ${
                      m.status === 'ativo' ? 'bg-green-600 text-white' :
                      m.status === 'provisionamento' ? 'bg-blue-600 text-white' :
                      'bg-white text-gray-300 border border-gray-100'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={20} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={20} /> :
                     <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-black text-gray-900 text-base uppercase tracking-tight">{m.nome} {m.ano}</h4>
                    <span className={`text-[9px] font-black uppercase tracking-[0.15em] px-2.5 py-1 rounded-lg ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status === 'provisionamento' ? 'Planejamento' : m.status}
                    </span>
                  </div>
                </div>

                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-base font-black text-gray-900 tracking-tighter">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">
                      {m.status === 'ativo' ? 'Contexto Real' : 'Fluxo Futuro'}
                    </p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 ml-auto text-gray-900 hover:gap-2 transition-all"
                  >
                    ACESSAR <ChevronRight size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  TrendingUp, 
  Banknote, 
  LockKeyhole, 
  Menu, 
  Wallet,
  RefreshCw,
  CalendarClock,
  Plus,
  Clock,
  CalendarDays
} from 'lucide-react';
import { supabaseClient } from './services/supabase';
import { Month } from './types';
import Overview from './components/Overview';
import Expenses from './components/Expenses';
import Revenue from './components/Revenue';
import Banks from './components/Banks';
import Closing from './components/Closing';
import Installments from './components/Installments';

const App: React.FC = () => {
  const [view, setView] = useState<string>('overview');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeMonth, setActiveMonth] = useState<Month | null>(null);
  const [provisionMonth, setProvisionMonth] = useState<Month | null>(null);
  const [currentContextMonth, setCurrentContextMonth] = useState<Month | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshKey, setRefreshKey] = useState(0);
  const [triggerAdd, setTriggerAdd] = useState(0);

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    setLoading(true);
    try {
      const { data: meses } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      let active = meses?.find((m: Month) => m.status === 'ativo');

      // Se não houver mês ativo, inicializa com DEZEMBRO/2025 conforme solicitado
      if (!meses || meses.length === 0 || !active) {
        const { data } = await supabaseClient
          .from('meses')
          .insert([{ nome: 'DEZEMBRO', ano: 2025, status: 'ativo' }])
          .select()
          .single();
        active = data;
      }

      // Lógica de Provisionamento e Virada de Ano (Ex: Dez/2025 -> Jan/2026)
      if (active) {
        const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
        let idx = meses_nomes.indexOf(active.nome.toUpperCase());
        let nextIdx = (idx + 1) % 12;
        let nextYear = idx === 11 ? active.ano + 1 : active.ano;
        const nextMonthName = meses_nomes[nextIdx];

        let prov = meses?.find(m => m.nome.toUpperCase() === nextMonthName && m.ano === nextYear);

        if (!prov) {
          const { data: newProv } = await supabaseClient
            .from('meses')
            .insert([{ nome: nextMonthName, ano: nextYear, status: 'provisionamento' }])
            .select()
            .single();
          prov = newProv;
        }

        setActiveMonth(active);
        setProvisionMonth(prov || null);

        // Mantém o contexto no mês atual se ele ainda for válido, senão reseta para o ativo
        if (!currentContextMonth || (currentContextMonth.id !== active.id && currentContextMonth.id !== prov?.id && currentContextMonth.status !== 'fechado')) {
          setCurrentContextMonth(active);
        }
      }
    } catch (error) {
      console.error("Erro na inicialização:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleGlobalRefresh = () => {
    setRefreshKey(prev => prev + 1);
    init();
  };

  const handleNavigate = (newView: string) => {
    setView(newView);
    setIsSidebarOpen(false);
  };

  const handleContextChange = (month: Month) => {
    // White Label Reset: Força a limpeza de todo o estado mudando a key dos componentes
    setCurrentContextMonth(month);
    setRefreshKey(prev => prev + 1);
  };

  const onAddClick = () => {
    setTriggerAdd(prev => prev + 1);
  };

  if (loading || !currentContextMonth) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-[#F8F9FA]">
        <div className="flex flex-col items-center gap-4">
          <div className="h-14 w-14 animate-spin rounded-full border-[5px] border-gray-900 border-t-transparent"></div>
          <p className="font-black text-gray-400 uppercase tracking-[0.2em] text-[10px]">Carregando Contexto...</p>
        </div>
      </div>
    );
  }

  const showAddAction = ['expenses', 'revenue', 'installments', 'banks'].includes(view);
  const canEdit = currentContextMonth.status !== 'fechado';

  return (
    <div className="flex h-screen bg-[#F8F9FA] overflow-hidden text-gray-900">
      {/* Sidebar Mobile Toggle */}
      {!isSidebarOpen && (
        <button 
          className="fixed bottom-8 left-8 z-50 p-5 bg-gray-900 text-white rounded-[2rem] shadow-2xl lg:hidden active:scale-90 transition-transform"
          onClick={() => setIsSidebarOpen(true)}
        >
          <Menu size={24} />
        </button>
      )}

      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-md z-30 lg:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      {/* Navegação Lateral */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-72 bg-white border-r border-gray-100 transform transition-transform duration-500 ease-in-out lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full p-8">
          <div className="flex items-center gap-4 mb-12">
            <div className="bg-gray-900 text-white p-3 rounded-[1.2rem] shadow-xl shadow-gray-200">
              <Wallet size={24} />
            </div>
            <div>
              <span className="text-2xl font-black tracking-tighter uppercase block leading-none">M&D</span>
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none">Finanças</span>
            </div>
          </div>

          <nav className="flex-1 space-y-1.5">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 ml-3">Principal</p>
            <NavItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={view === 'overview'} onClick={() => handleNavigate('overview')} />
            <NavItem icon={<Receipt size={20} />} label="Despesas" active={view === 'expenses'} onClick={() => handleNavigate('expenses')} />
            <NavItem icon={<TrendingUp size={20} />} label="Receitas" active={view === 'revenue'} onClick={() => handleNavigate('revenue')} />

            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-10 mb-4 ml-3">Gestão</p>
            <NavItem icon={<Banknote size={20} />} label="Cartões" active={view === 'banks'} onClick={() => handleNavigate('banks')} />
            <NavItem icon={<CalendarClock size={20} />} label="Parcelas" active={view === 'installments'} onClick={() => handleNavigate('installments')} />

            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-10 mb-4 ml-3">Histórico</p>
            <NavItem icon={<Clock size={20} />} label="Arquivo" active={view === 'closing'} onClick={() => handleNavigate('closing')} />
          </nav>
        </div>
      </aside>

      {/* Área Principal */}
      <main className="flex-1 overflow-y-auto relative no-scrollbar">
        {/* HEADER LINHA DO TEMPO */}
        <div className="sticky top-0 z-20 bg-white/90 backdrop-blur-xl border-b border-gray-100 px-6 py-4 lg:px-12 lg:py-6">
          <div className="max-w-6xl mx-auto flex flex-col sm:flex-row items-center justify-between gap-6">

            {/* Context Switcher (Timeline Header) */}
            <div className="w-full sm:flex-1 flex items-center justify-between gap-2 bg-gray-100/50 p-2 rounded-[2rem] border border-gray-200/50">
              {activeMonth && (
                <button 
                  onClick={() => handleContextChange(activeMonth)}
                  className={`flex flex-col items-center justify-center min-w-[140px] px-6 py-2.5 rounded-[1.5rem] transition-all duration-300 ${
                    currentContextMonth.id === activeMonth.id 
                    ? 'bg-white shadow-xl shadow-gray-200 border border-green-100' 
                    : 'opacity-40 hover:opacity-100 hover:bg-white/50'
                  }`}
                >
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentContextMonth.id === activeMonth.id ? 'text-green-600' : 'text-gray-400'}`}>
                    Ativo
                  </span>
                  <span className="text-sm font-black text-gray-800 uppercase leading-none mt-1">
                    {activeMonth.nome} {activeMonth.ano}
                  </span>
                </button>
              )}

              {provisionMonth && (
                <button 
                  onClick={() => handleContextChange(provisionMonth)}
                  className={`flex flex-col items-center justify-center min-w-[140px] px-6 py-2.5 rounded-[1.5rem] transition-all duration-300 ${
                    currentContextMonth.id === provisionMonth.id 
                    ? 'bg-white shadow-xl shadow-gray-200 border border-blue-100' 
                    : 'opacity-40 hover:opacity-100 hover:bg-white/50'
                  }`}
                >
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentContextMonth.id === provisionMonth.id ? 'text-blue-600' : 'text-gray-400'}`}>
                    Planejamento
                  </span>
                  <span className="text-sm font-black text-gray-800 uppercase leading-none mt-1">
                    {provisionMonth.nome} {provisionMonth.ano}
                  </span>
                </button>
              )}
            </div>

            {/* Ações Globais */}
            <div className="flex items-center gap-3">
              {showAddAction && canEdit && (
                <button 
                  onClick={onAddClick}
                  className="bg-gray-900 text-white p-4 rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all"
                  title="Novo Lançamento"
                >
                  <Plus size={22} />
                </button>
              )}
              <button 
                onClick={handleGlobalRefresh}
                className="p-4 bg-white border border-gray-200 rounded-2xl text-gray-400 hover:text-gray-900 transition-all shadow-sm"
              >
                <RefreshCw size={22} />
              </button>
            </div>
          </div>
        </div>

        {/* CONTEÚDO DINÂMICO (White Label Isolado por Mês) */}
        <div className="p-6 lg:p-12 max-w-6xl mx-auto">
          {/* Alerta de Mês Fechado */}
          {currentContextMonth.status === 'fechado' && (
            <div className="mb-10 bg-amber-50 border border-amber-200/50 p-6 rounded-[2rem] flex items-center gap-4 text-amber-800 shadow-sm animate-in fade-in slide-in-from-top-4">
              <div className="bg-amber-100 p-3 rounded-2xl"><LockKeyhole size={24} /></div>
              <div>
                <p className="text-sm font-black uppercase tracking-tighter">Histórico (Modo Leitura)</p>
                <p className="text-[11px] font-bold opacity-70 uppercase tracking-widest">Este ciclo foi encerrado. Novos dados não podem ser adicionados.</p>
              </div>
            </div>
          )}

          {/* Renderização Condicional com Reset de State via Key */}
          {view === 'overview' && <Overview key={`ov-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} refresh={handleGlobalRefresh} />}
          {view === 'expenses' && <Expenses key={`ex-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'revenue' && <Revenue key={`rv-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'banks' && <Banks key={`bk-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'installments' && <Installments key={`in-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'closing' && <Closing key={`cl-${refreshKey}`} currentMonth={activeMonth!} onSelectMonth={handleContextChange} onRefresh={init} />}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-5 py-4.5 rounded-2xl transition-all duration-500 font-bold text-sm ${
      active 
        ? 'bg-gray-900 text-white shadow-2xl shadow-gray-400' 
        : 'text-gray-400 hover:bg-gray-50 hover:text-gray-600'
    }`}
  >
    <span className={active ? 'text-white' : 'text-gray-400'}>{icon}</span>
    <span className="uppercase tracking-widest text-[11px] font-black">{label}</span>
  </button>
);

export default App;
